export const analyzeClaim = async (
  text: string,
  imageBase64?: string
): Promise<Omit<FactCheckResult, 'id' | 'timestamp' | 'author'>> => {

  const parts: any[] = [];
  if (imageBase64) {
    parts.push({ inlineData: { data: imageBase64, mimeType: "image/jpeg" } });
  }

  parts.push({ 
    text: `Claim Analysis Request: "${text}". 
