  });

  try {
    // Specify the generic type for retryOperation to ensure 'response' is correctly typed as GenerateContentResponse
    const response = await retryOperation<GenerateContentResponse>(() => ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts }],
      config: {
        systemInstruction: "You are a world-class investigative journalist and fact-checker. Use Google Search to verify claims against reputable sources like Reuters, AP, and BBC. Always prioritize accuracy over speed.",
        tools: [{ googleSearch: {} }],
        temperature: 0,
        thinkingConfig: { thinkingBudget: 4000 }
      }
    }));

    // Access properties on GenerateContentResponse; now properly typed
    const jsonResponse = JSON.parse(cleanJsonString(response.text || "{}"));
