const retryOperation = async <T>(operation: () => Promise<T>, retries = 2, delay = 1000): Promise<T> => {
  for (let i = 0; i < retries; i++) {
    try {
      return await operation();
    } catch (error) {
      if (i === retries - 1) throw error;
      await new Promise(resolve => setTimeout(resolve, delay * (i + 1)));
    }
  }
  throw new Error("Operation failed after retries");
};

/**
 * Robust JSON extractor that finds the outermost [ or { to bypass
 * any conversational text or markdown blocks added by the model.
 */
const cleanJsonString = (text: string): string => {
  if (!text) return "";

  // Find the first occurrence of either [ or {
  const firstBracket = text.indexOf('[');
  const firstBrace = text.indexOf('{');

  let start = -1;
  let end = -1;

  // Determine if we are looking for an array or an object based on which comes first
  if (firstBracket !== -1 && (firstBrace === -1 || firstBracket < firstBrace)) {
      start = firstBracket;
      end = text.lastIndexOf(']');
  } else if (firstBrace !== -1) {
      start = firstBrace;
      end = text.lastIndexOf('}');
  }

  if (start !== -1 && end !== -1 && end > start) {
      return text.substring(start, end + 1);
  }

  return text.trim();
};

const getNewsImage = (keyword: string): string => {
  const seed = encodeURIComponent(keyword.substring(0, 15));
  return `https://picsum.photos/seed/${seed}/800/450`;
};

