/**
 * Robust JSON extractor that handles trailing grounding citations and conversational text.
 * It finds the balanced outermost object or array.
 */
const cleanJsonString = (text: string): string => {
  if (!text) return "";

  const firstBrace = text.indexOf('{');
  const firstBracket = text.indexOf('[');

  let start = -1;
  let end = -1;
  let stack = 0;
  let charOpen = '';
  let charClose = '';

  // Determine if we are starting with an object or an array
  if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
    start = firstBrace;
    charOpen = '{';
    charClose = '}';
  } else if (firstBracket !== -1) {
    start = firstBracket;
    charOpen = '[';
    charClose = ']';
  }

  if (start === -1) return text.trim();

  for (let i = start; i < text.length; i++) {
    if (text[i] === charOpen) stack++;
    if (text[i] === charClose) {
      stack--;
      if (stack === 0) {
        end = i;
        break;
      }
    }
  }

  if (start !== -1 && end !== -1) {
    return text.substring(start, end + 1);
  }

  return text.trim();
};

