import React, { useState, useRef, useEffect } from 'react';
import { Loader2, Search, Image as ImageIcon, ExternalLink, ShieldCheck, Cpu } from 'lucide-react';
import { analyzeClaim } from '../services/geminiService';
import { FactCheckResult } from '../types';
import { VerdictBadge } from '../components/VerdictBadge';
import { useAuth } from '../context/AuthContext';

export const Verify: React.FC = () => {
  const [claim, setClaim] = useState('');
  const [image, setImage] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [status, setStatus] = useState('');
  const [result, setResult] = useState<FactCheckResult | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { user, submitCheck } = useAuth();

  useEffect(() => {
    return () => {
      if (previewUrl?.startsWith('blob:')) URL.revokeObjectURL(previewUrl);
    };
  }, [previewUrl]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const file = e.target.files[0];
      setImage(file);
      setPreviewUrl(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!claim && !image) return;

    setIsAnalyzing(true);
    setResult(null);
    setStatus('Initializing Deep Search...');

    let base64Image = undefined;
    if (image) {
      const reader = new FileReader();
      base64Image = await new Promise<string>((resolve) => {
        reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(image);
      });
    }

    try {
      // Simulation of reasoning phases for better UX
      setTimeout(() => setStatus('Forensic Evidence Check...'), 1500);
      setTimeout(() => setStatus('Running Deep Reasoning...'), 3500);

      const analysis = await analyzeClaim(claim, base64Image);

      const newCheck: FactCheckResult = {
        ...analysis,
        id: Date.now().toString(),
        timestamp: Date.now(),
        author: user ? user.name : 'Citizen Auditor'
      };

      submitCheck(newCheck);
      setResult(newCheck);
    } catch (err) {
      console.error(err);
      alert("Analysis engine timed out. The claim might be too complex or server load is high. Please retry.");
    } finally {
      setIsAnalyzing(false);
      setStatus('');
    }
  };

  return (
    <div className="max-w-3xl mx-auto px-4 py-12">
      <div className="text-center mb-12">
        <div className="inline-flex items-center justify-center p-3 bg-primary-900/20 text-primary-400 rounded-full mb-4 border border-primary-800">
            <Cpu className="w-8 h-8" />
        </div>
        <h1 className="text-3xl md:text-5xl font-black text-white mb-4 tracking-tighter">
            PROACTIVE VERIFICATION
        </h1>
        <p className="text-slate-400 text-lg max-w-xl mx-auto leading-relaxed">
          Powered by Gemini 3 Pro with deep reasoning. Submit text, images, or social links for instant forensic analysis.
        </p>
      </div>

      <div className="bg-slate-900/50 backdrop-blur-sm rounded-2xl shadow-card border border-slate-800 overflow-hidden mb-12">
         <div className="p-8">
            <form onSubmit={handleSubmit} className="space-y-6">
                <div>
                    <label className="block text-xs font-black text-slate-500 mb-2 uppercase tracking-widest">
                        Claim Statement or URL
                    </label>
                    <textarea
                        value={claim}
                        onChange={(e) => setClaim(e.target.value)}
                        placeholder="e.g., 'Viral video of robots in New York' or a link to a tweet..."
                        className="w-full h-32 px-4 py-3 bg-slate-950 border border-slate-800 text-white rounded-xl focus:ring-2 focus:ring-primary-600 outline-none transition-all resize-none text-base font-medium placeholder-slate-700"
                    />
                </div>

                <div>
                    <div 
                        onClick={() => fileInputRef.current?.click()}
                        className={`relative border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-all ${previewUrl ? 'border-primary-600 bg-primary-950' : 'border-slate-800 hover:border-primary-600 hover:bg-slate-950'}`}
                    >
                        {previewUrl ? (
                            <img src={previewUrl} alt="Preview" className="max-h-64 mx-auto rounded-lg shadow-xl" />
                        ) : (
                            <div className="space-y-3">
                                <ImageIcon className="w-10 h-10 text-slate-700 mx-auto" />
                                <p className="text-sm font-bold text-slate-500">Upload screenshot for visual forensic check</p>
                            </div>
                        )}
                        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageChange} />
                    </div>
                </div>

                <button
                    type="submit"
                    disabled={isAnalyzing || (!claim && !image)}
                    className="w-full py-4 rounded-xl font-black text-xl bg-primary-600 text-white hover:bg-primary-500 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-4 transition-all shadow-lg shadow-primary-900/20"
                >
                    {isAnalyzing ? (
                        <>
                            <Loader2 className="animate-spin w-6 h-6" />
                            <span className="animate-pulse">{status}</span>
                        </>
                    ) : (
                        <>
                            <ShieldCheck className="w-6 h-6" />
                            <span>EXECUTE ANALYSIS</span>
                        </>
                    )}
                </button>
            </form>
         </div>
      </div>

      {result && (
        <div className="mt-12 animate-fade-in-up">
           <div className="bg-slate-900 rounded-2xl border border-slate-800 shadow-2xl overflow-hidden">
               <div className="h-2 bg-gradient-to-r from-primary-600 via-indigo-500 to-purple-600"></div>
               <div className="p-8">
                   <div className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-10 pb-10 border-b border-slate-800">
                       <div className="space-y-3">
                           <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest block">Final Intelligence Verdict</span>
                           <VerdictBadge verdict={result.verdict} className="text-lg px-6 py-2.5" />
                       </div>
