export const fetchTrendingDebunks = async (forceRefresh = false): Promise<FactCheckResult[]> => {
  if (!forceRefresh && !db.isCacheStale()) {
    const cached = db.getTrending();
    if (cached.length > 0) return cached;
  }
  try {
     const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: "Identify 4 trending viral claims. Return JSON array: [{headline, summary, verdict (TRUE/FALSE/MISLEADING), sourceName, bias (NEUTRAL/LEAN_LEFT/LEAN_RIGHT/POLARIZING)}]" }] }],
      config: { tools: [{ googleSearch: {} }], temperature: 0.4 }
    });
    const data = JSON.parse(cleanJsonString(response.text || "[]"));
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const webSources: Source[] = groundingChunks.filter((c: any) => c.web?.uri).map((c: any) => ({ title: c.web.title || "Ref", uri: c.web.uri }));

    const results: FactCheckResult[] = data.map((item: any, i: number) => {
      const total = 500 + Math.floor(Math.random() * 2000);
      return {
        id: `trend-${Date.now()}-${i}`,
        claim: item.headline,
        verdict: item.verdict as VerdictType,
        explanation: item.summary,
        headline: item.headline,
        keyPoints: ["AI verified via search grounding", "Cross-referenced metadata"],
        sources: webSources.slice(i, i + 2).length > 0 ? webSources.slice(i, i + 2) : [{ title: item.sourceName || "Report", uri: "#" }],
        timestamp: Date.now(),
        confidenceScore: 85 + Math.floor(Math.random() * 14),
        biasRating: item.bias || 'NEUTRAL',
        communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
        author: "AI News Agent",
        imageUrl: getNewsImage(item.headline)
      };
    });
    db.saveTrending(results);
    return results;
  } catch (e) { return db.getTrending(); }
};

export const analyzeClaim = async (text: string, imageBase64?: string): Promise<Omit<FactCheckResult, 'id' | 'timestamp' | 'author'>> => {
  const startTime = Date.now();
  const parts: any[] = [];
  if (imageBase64) parts.push({ inlineData: { data: imageBase64, mimeType: "image/jpeg" } });
  parts.push({ text: `Analyze this news claim: "${text}". Detect if it is fake/misleading. Perform deep search. Return JSON ONLY: { "verdict": "TRUE"|"FALSE"|"MISLEADING"|"UNVERIFIED", "headline": "...", "summary": "...", "keyPoints": ["...", "..."], "confidenceScore": 0-100, "bias": "NEUTRAL"|"LEAN_LEFT"|"LEAN_RIGHT"|"POLARIZING" }` });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts }],
      config: {
        systemInstruction: "You are an Elite Forensic Fact-Checker. Use Google Search to verify claims. Your output must be strict JSON. Be skeptical of unverified social media viral posts.",
        tools: [{ googleSearch: {} }],
        temperature: 0,
        thinkingConfig: { thinkingBudget: 8000 }
      }
    });

    const json = JSON.parse(cleanJsonString(response.text || "{}"));
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources: Source[] = Array.from(new Map<string, Source>(chunks.filter((c: any) => c.web?.uri).map((c: any) => [c.web.uri, { title: c.web.title || "Ref", uri: c.web.uri }])).values());

    return {
      claim: text || "Visual Scan",
      verdict: (json.verdict?.toUpperCase() as VerdictType) || VerdictType.UNVERIFIED,
      explanation: json.summary || "No clear debunking found.",
      headline: json.headline || "Intelligence Brief",
      keyPoints: json.keyPoints || ["Analyzing global databases..."],
      confidenceScore: json.confidenceScore || 70,
      biasRating: json.bias || 'NEUTRAL',
      sources: sources,
      imageUrl: imageBase64 ? `data:image/jpeg;base64,${imageBase64}` : undefined,
      communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
      analysisTime: Date.now() - startTime
    };
  } catch (error) { throw error; }
};

