import { User, FactCheckResult, TickerItem, Activity } from '../types';

const KEYS = {
  USERS: 'fp_u_v3',
  CHECKS: 'fp_c_v3',
  TRENDING: 'fp_t_v3',
  TICKER: 'fp_k_v3',
  LAST_FETCH: 'fp_lf_v3',
  ACTIVITIES: 'fp_a_v3'
};

const CACHE_DURATION = 15 * 60 * 1000; 
const MAX_HISTORY = 15;
const MAX_ACTIVITIES = 20;

export const db = {
  getUsers: (): User[] => {
    const d = localStorage.getItem(KEYS.USERS);
    return d ? JSON.parse(d) : [];
  },

  saveUsers: (users: User[]) => {
    localStorage.setItem(KEYS.USERS, JSON.stringify(users));
  },

  getUserByEmail: (email: string): User | undefined => {
    return db.getUsers().find(u => u.email.toLowerCase() === email.trim().toLowerCase());
  },

  getLocalChecks: (): FactCheckResult[] => {
    const d = localStorage.getItem(KEYS.CHECKS);
    return d ? JSON.parse(d) : [];
  },

  saveLocalCheck: (check: FactCheckResult) => {
    const checks = db.getLocalChecks();
    // Strip base64 to save storage space
    const lightCheck = { ...check, imageUrl: check.imageUrl?.startsWith('data:') ? undefined : check.imageUrl };
    const updated = [lightCheck, ...checks].slice(0, MAX_HISTORY);
    localStorage.setItem(KEYS.CHECKS, JSON.stringify(updated));
  },

  getTrending: (): FactCheckResult[] => {
    const d = localStorage.getItem(KEYS.TRENDING);
    return d ? JSON.parse(d) : [];
  },

  saveTrending: (checks: FactCheckResult[]) => {
    localStorage.setItem(KEYS.TRENDING, JSON.stringify(checks.slice(0, 10)));
    localStorage.setItem(KEYS.LAST_FETCH, Date.now().toString());
  },

  isCacheStale: (): boolean => {
      const lf = localStorage.getItem(KEYS.LAST_FETCH);
      return !lf || (Date.now() - parseInt(lf)) > CACHE_DURATION;
  },

  getTicker: (): TickerItem[] => {
    const d = localStorage.getItem(KEYS.TICKER);
    return d ? JSON.parse(d) : [];
  },

  saveTicker: (items: TickerItem[]) => {
    localStorage.setItem(KEYS.TICKER, JSON.stringify(items.slice(0, 10)));
  },

  updateVote: (checkId: string, option: 'trueVotes' | 'falseVotes' | 'misleadingVotes') => {
    const lists = [KEYS.CHECKS, KEYS.TRENDING];
    lists.forEach(key => {
        const data = localStorage.getItem(key);
        if (data) {
            const list: FactCheckResult[] = JSON.parse(data);
            const idx = list.findIndex(c => c.id === checkId);
            if (idx !== -1) {
                list[idx].communityPoll[option]++;
                list[idx].communityPoll.total++;
                localStorage.setItem(key, JSON.stringify(list));
            }
        }
    });
  },

  deleteContent: (id: string) => {
      [KEYS.CHECKS, KEYS.TRENDING].forEach(key => {
          const data = localStorage.getItem(key);
          if (data) {
              const filtered = JSON.parse(data).filter((c: any) => c.id !== id);
              localStorage.setItem(key, JSON.stringify(filtered));
          }
      });
  },

  // --- NEW ACTIVITY & REAL-TIME TRACKING ---
  getActivities: (): Activity[] => {
    const d = localStorage.getItem(KEYS.ACTIVITIES);
    return d ? JSON.parse(d) : [
      { id: '1', userId: 'bot', userName: 'Maria S.', action: 'verified viral link from X', timestamp: Date.now() - 120000 },
      { id: '2', userId: 'bot', userName: 'Kevin J.', action: 'flagged misleading post', timestamp: Date.now() - 600000 }
    ];
  },

  logActivity: (userId: string, userName: string, action: string) => {
    const activities = db.getActivities();
    const newActivity: Activity = {
      id: `act-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      userId,
      userName,
      action,
      timestamp: Date.now()
    };
    const updated = [newActivity, ...activities].slice(0, MAX_ACTIVITIES);
    localStorage.setItem(KEYS.ACTIVITIES, JSON.stringify(updated));
  }
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { User, FactCheckResult, Activity } from '../types';
import { fetchTrendingDebunks } from '../services/geminiService';
import { db } from '../services/db';

interface AuthContextType {
  user: User | null;
  checkEmailExists: (email: string) => boolean;
  login: (email: string, name?: string, rememberMe?: boolean) => void;
  loginAdmin: (password: string) => boolean; 
  logout: () => void;
  castVote: (checkId: string, option: 'trueVotes' | 'falseVotes' | 'misleadingVotes') => void;
  submitCheck: (check: FactCheckResult) => void;
  activeUsersCount: number;
  getAllUsers: () => User[];
  deleteUser: (userId: string) => void;
  getAllContent: () => Promise<FactCheckResult[]>;
  deleteContent: (contentId: string) => void;
  getRecentActivities: () => Activity[];
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);
const CURRENT_USER_KEY = 'factpulse_session_v3';

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [activeUsersCount, setActiveUsersCount] = useState(() => 1432 + Math.floor(Math.random() * 200));

  // Simulation of "Real-time" traffic pulse
  useEffect(() => {
    const interval = setInterval(() => {
      setActiveUsersCount(prev => {
        const delta = Math.floor(Math.random() * 21) - 10;
        return Math.max(1100, Math.min(2500, prev + delta));
      });
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  // Load session on mount
  useEffect(() => {
    let storedSession = localStorage.getItem(CURRENT_USER_KEY);
    if (!storedSession) {
        storedSession = sessionStorage.getItem(CURRENT_USER_KEY);
    }

    if (storedSession) {
      try {
        const sessionUser = JSON.parse(storedSession);
        const freshUser = db.getUsers().find(u => u.id === sessionUser.id) || sessionUser;
        setUser(freshUser);
      } catch (e) {
          console.error("Session parse error", e);
      }
    }
  }, []);

  const checkEmailExists = (email: string): boolean => {
    return !!db.getUserByEmail(email);
  };

  const login = (email: string, name?: string, rememberMe: boolean = false) => {
    const existingUser = db.getUserByEmail(email);
    let activeUser: User;
    const isAdmin = email.trim().toLowerCase() === 'admin@factpulse.com';

    if (existingUser) {
      activeUser = { ...existingUser, isAdmin }; 
    } else {
      if (!name) throw new Error("Name is required to create a new account.");
      activeUser = {
        id: `user-${Date.now()}`,
        name,
        email: email.trim().toLowerCase(),
        initials: name.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase(),
        level: 'Truth Seeker',
        votes: {},
        joinedAt: Date.now(),
        stats: { points: 100, reportsFiled: 0, accuracyRate: 100 },
        isAdmin
      };

      const allUsers = db.getUsers();
      db.saveUsers([...allUsers, activeUser]);
      db.logActivity(activeUser.id, activeUser.name, 'joined the FactPulse network');
    }

    setUser(activeUser);
    const targetStorage = rememberMe ? localStorage : sessionStorage;
    targetStorage.setItem(CURRENT_USER_KEY, JSON.stringify(activeUser));
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem(CURRENT_USER_KEY);
    sessionStorage.removeItem(CURRENT_USER_KEY);
  };

  const castVote = (checkId: string, option: 'trueVotes' | 'falseVotes' | 'misleadingVotes') => {
    if (!user) return;
    const pointsGain = 10;
    const updatedUser: User = {
        ...user,
        votes: { ...user.votes, [checkId]: option },
        stats: { ...user.stats, points: user.stats.points + pointsGain }
    };
    updateUserStateAndDB(updatedUser);
    db.updateVote(checkId, option);
    db.logActivity(user.id, user.name, `cast a vote on intelligence #${checkId.substring(0, 4)}`);
  };

  const submitCheck = (check: FactCheckResult) => {
    db.saveLocalCheck(check);
    if (user) {
        const updatedUser: User = {
            ...user,
            stats: { ...user.stats, points: user.stats.points + 50, reportsFiled: user.stats.reportsFiled + 1 }
        };
        updateUserStateAndDB(updatedUser);
        db.logActivity(user.id, user.name, `submitted forensic report: "${check.headline?.substring(0, 30)}..."`);
    }
  };

  const updateUserStateAndDB = (updatedUser: User) => {
    setUser(updatedUser);
    const store = localStorage.getItem(CURRENT_USER_KEY) ? localStorage : sessionStorage;
    store.setItem(CURRENT_USER_KEY, JSON.stringify(updatedUser));
    const dbUsers = db.getUsers();
    const idx = dbUsers.findIndex(u => u.id === updatedUser.id);
    if (idx >= 0) {
        dbUsers[idx] = updatedUser;
        db.saveUsers(dbUsers);
    }
  };

  return (
    <AuthContext.Provider value={{ 
        user, login, logout, checkEmailExists, castVote, submitCheck, activeUsersCount,
        getAllUsers: () => db.getUsers(),
        deleteUser: (id) => db.saveUsers(db.getUsers().filter(u => u.id !== id)),
        getAllContent: async () => [...db.getLocalChecks(), ...(await fetchTrendingDebunks(false))],
        deleteContent: (id) => db.deleteContent(id),
        getRecentActivities: () => db.getActivities(),
        loginAdmin: (p) => { 
          if (p === 'admin123') { 
            login('admin@factpulse.com', 'System Admin', true); 
            return true; 
          } return false; 
        }
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth error');
  return context;
};

