import { User, FactCheckResult, TickerItem, Activity } from '../types';

/**
 * DATABASE SCHEMA VERSION 4.0
 * Domain-Driven Storage Architecture
 */
const STORES = {
  USER_DATA: 'fp_users_v4',
  FEED_DATA: 'fp_content_v4',
  TRENDING_CACHE: 'fp_trending_v4',
  SYSTEM_TICKER: 'fp_ticker_v4',
  ACTIVITY_LOG: 'fp_activity_v4',
  META: 'fp_meta_v4'
};

const CACHE_TTL = 1000 * 60 * 15; // 15 Minutes
const MAX_LOG_SIZE = 50;

/**
 * Internal Storage Engine with Safety Guards
 */
const storage = {
  get: <T>(key: string, fallback: T): T => {
    try {
      const data = localStorage.getItem(key);
      return data ? JSON.parse(data) : fallback;
    } catch (e) {
      console.error(`DB READ ERROR [${key}]:`, e);
      return fallback;
    }
  },
  set: <T>(key: string, value: T): void => {
    try {
      localStorage.setItem(key, JSON.stringify(value));
    } catch (e) {
      console.error(`DB WRITE ERROR [${key}]:`, e);
      // If quota exceeded, clear non-essential caches
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        localStorage.removeItem(STORES.TRENDING_CACHE);
        localStorage.removeItem(STORES.SYSTEM_TICKER);
      }
    }
  }
};

/**
 * Domain Repositories
 */
export const db = {
  // --- USER REPOSITORY ---
  users: {
    all: () => storage.get<User[]>(STORES.USER_DATA, []),

    save: (user: User) => {
      const users = db.users.all();
      const idx = users.findIndex(u => u.id === user.id);
      if (idx > -1) users[idx] = user;
      else users.push(user);
      storage.set(STORES.USER_DATA, users);
    },

    findByEmail: (email: string) => 
      db.users.all().find(u => u.email.toLowerCase() === email.trim().toLowerCase()),

    delete: (id: string) => 
      storage.set(STORES.USER_DATA, db.users.all().filter(u => u.id !== id)),

    getLeaderboard: () => {
        return [...db.users.all()]
            .sort((a, b) => b.stats.points - a.stats.points)
            .slice(0, 100);
    }
  },

  // --- CONTENT REPOSITORY ---
  content: {
    getFeed: () => storage.get<FactCheckResult[]>(STORES.FEED_DATA, []),

    saveCheck: (check: FactCheckResult) => {
      const feed = db.content.getFeed();
      // Ensure we don't store massive base64 strings in the long-term feed
      const optimizedCheck = { 
        ...check, 
        imageUrl: check.imageUrl?.startsWith('data:image') ? undefined : check.imageUrl 
      };
      storage.set(STORES.FEED_DATA, [optimizedCheck, ...feed].slice(0, 25));
    },

    getTrending: () => storage.get<FactCheckResult[]>(STORES.TRENDING_CACHE, []),

    saveTrending: (data: FactCheckResult[]) => {
      storage.set(STORES.TRENDING_CACHE, data);
      storage.set(STORES.META, { ...storage.get(STORES.META, {}), lastFetch: Date.now() });
    },

    updateVote: (id: string, option: keyof FactCheckResult['communityPoll']) => {
      // Transactional update across all possible stores where content might live
      [STORES.FEED_DATA, STORES.TRENDING_CACHE].forEach(key => {
        const items = storage.get<FactCheckResult[]>(key, []);
        const item = items.find(i => i.id === id);
        if (item) {
          (item.communityPoll[option] as number)++;
          item.communityPoll.total++;
          storage.set(key, items);
        }
      });
    },

    isCacheStale: () => {
      const meta = storage.get<{lastFetch?: number}>(STORES.META, {});
      return !meta.lastFetch || (Date.now() - meta.lastFetch > CACHE_TTL);
    },

    delete: (id: string) => {
        [STORES.FEED_DATA, STORES.TRENDING_CACHE].forEach(key => {
            const items = storage.get<FactCheckResult[]>(key, []);
            storage.set(key, items.filter(i => i.id !== id));
        });
    }
  },

  // --- ANALYTICS & ACTIVITY ---
  analytics: {
    getTicker: () => storage.get<TickerItem[]>(STORES.SYSTEM_TICKER, []),

    saveTicker: (items: TickerItem[]) => storage.set(STORES.SYSTEM_TICKER, items),

    getLogs: () => storage.get<Activity[]>(STORES.ACTIVITY_LOG, []),

    log: (userId: string, userName: string, action: string) => {
      const logs = db.analytics.getLogs();
      const entry: Activity = {
        id: `log-${Date.now()}-${Math.random().toString(36).substring(7)}`,
        userId,
        userName,
        action,
        timestamp: Date.now()
      };
      storage.set(STORES.ACTIVITY_LOG, [entry, ...logs].slice(0, MAX_LOG_SIZE));
    }
  }
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { User, FactCheckResult, Activity } from '../types';
import { fetchTrendingDebunks } from '../services/geminiService';
import { db } from '../services/db';

interface AuthContextType {
  user: User | null;
  checkEmailExists: (email: string) => boolean;
  login: (email: string, name?: string, rememberMe?: boolean) => void;
  loginAdmin: (password: string) => boolean; 
  logout: () => void;
  castVote: (checkId: string, option: 'trueVotes' | 'falseVotes' | 'misleadingVotes') => void;
  submitCheck: (check: FactCheckResult) => void;
  activeUsersCount: number;
  getAllUsers: () => User[];
  deleteUser: (userId: string) => void;
  getAllContent: () => Promise<FactCheckResult[]>;
  deleteContent: (contentId: string) => void;
  getRecentActivities: () => Activity[];
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);
const SESSION_KEY = 'fp_active_session_v4';

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [activeUsersCount, setActiveUsersCount] = useState(() => 1250 + Math.floor(Math.random() * 300));

  // Traffic Pulse Logic (Simulated High-Concurrency)
  useEffect(() => {
    const timer = setInterval(() => {
      setActiveUsersCount(prev => {
        const drift = Math.floor(Math.random() * 31) - 15;
        return Math.max(1000, Math.min(3000, prev + drift));
      });
    }, 5000);
    return () => clearInterval(timer);
  }, []);

  // Hydrate session
  useEffect(() => {
    const raw = localStorage.getItem(SESSION_KEY) || sessionStorage.getItem(SESSION_KEY);
    if (raw) {
      try {
        const session = JSON.parse(raw);
        const fresh = db.users.findByEmail(session.email);
        if (fresh) setUser({ ...fresh, isAdmin: session.isAdmin });
      } catch (e) { console.error("Session restoration failed", e); }
    }
  }, []);

  const checkEmailExists = (email: string) => !!db.users.findByEmail(email);

  const login = (email: string, name?: string, rememberMe = false) => {
    const existing = db.users.findByEmail(email);
    let active: User;
    const isAdmin = email.toLowerCase() === 'admin@factpulse.com';

    if (existing) {
      active = { ...existing, isAdmin };
    } else {
      if (!name) throw new Error("Full name required for new node registration");
      active = {
        id: `node-${Date.now()}`,
        name,
        email: email.toLowerCase(),
        initials: name.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase(),
        level: 'Truth Seeker',
        votes: {},
        joinedAt: Date.now(),
        stats: { points: 100, reportsFiled: 0, accuracyRate: 100 },
        isAdmin
      };
      db.users.save(active);
      db.analytics.log(active.id, active.name, "registered as a new verification node");
    }

    setUser(active);
    const store = rememberMe ? localStorage : sessionStorage;
    store.setItem(SESSION_KEY, JSON.stringify(active));
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem(SESSION_KEY);
    sessionStorage.removeItem(SESSION_KEY);
  };

  const castVote = (checkId: string, option: 'trueVotes' | 'falseVotes' | 'misleadingVotes') => {
    if (!user) return;

    // 1. Update DB (Content Store)
    db.content.updateVote(checkId, option);

    // 2. Update User Profile (User Store)
    const updated: User = {
      ...user,
      votes: { ...user.votes, [checkId]: option },
      stats: { ...user.stats, points: user.stats.points + 10 }
    };
    db.users.save(updated);
    setUser(updated);

    // 3. Log System Activity
    db.analytics.log(user.id, user.name, `authenticated intelligence check #${checkId.substring(0, 5)}`);
  };

  const submitCheck = (check: FactCheckResult) => {
    db.content.saveCheck(check);
    if (user) {
      const updated: User = {
        ...user,
        stats: { ...user.stats, points: user.stats.points + 50, reportsFiled: user.stats.reportsFiled + 1 }
      };
      db.users.save(updated);
      setUser(updated);
      db.analytics.log(user.id, user.name, `pushed new forensic evidence: "${check.headline?.substring(0, 25)}..."`);
    }
  };

  return (
    <AuthContext.Provider value={{
      user, login, logout, checkEmailExists, castVote, submitCheck, activeUsersCount,
      getAllUsers: () => db.users.all(),
      deleteUser: (id) => db.users.delete(id),
      getAllContent: async () => [...db.content.getFeed(), ...(await fetchTrendingDebunks(false))],
      deleteContent: (id) => db.content.delete(id),
      getRecentActivities: () => db.analytics.getLogs(),
      loginAdmin: (pass: string) => {
        if (pass === 'admin123') {
          login('admin@factpulse.com', 'System Administrator', true);
          return true;
        }
        return false;
      }
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
};

