import React, { useState, useRef, useEffect } from 'react';
import { Loader2, Search, Image as ImageIcon, ExternalLink, ShieldCheck, Cpu, Globe, Link as LinkIcon, Fingerprint, Database, Zap } from 'lucide-react';
import { analyzeClaim } from '../services/geminiService';
import { FactCheckResult } from '../types';
import { VerdictBadge } from '../components/VerdictBadge';
import { useAuth } from '../context/AuthContext';

export const Verify: React.FC = () => {
  const [claim, setClaim] = useState('');
  const [image, setImage] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [status, setStatus] = useState('');
  const [result, setResult] = useState<FactCheckResult | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const statusIntervalRef = useRef<number | null>(null);
  const { user, submitCheck } = useAuth();

  useEffect(() => {
    return () => { 
      if (previewUrl?.startsWith('blob:')) URL.revokeObjectURL(previewUrl); 
      if (statusIntervalRef.current) clearInterval(statusIntervalRef.current);
    };
  }, [previewUrl]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const file = e.target.files[0];
      setImage(file);
      setPreviewUrl(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!claim && !image) return;

    setIsAnalyzing(true);
    setResult(null);

    // THE INTELLIGENCE PIPELINE
    const statusSequence = [
        "Initializing Forensic Handshake...",
        "Validating Source Integrity...",
        "Scraping Metadata & URL Citations...",
        "Extracting Digital Fingerprints...",
        "Cross-Referencing Global News Databases...",
        "Identifying Biased Language Patterns...",
        "Gemini 3 Deep Reasoning Active...",
        "Contextualizing Multi-Modal Evidence...",
        "Forensic Truth Correlation in Progress...",
        "Finalizing Intelligence Report..."
    ];

    let statusIdx = 0;
    setStatus(statusSequence[0]);

    // Cycle through statuses with varying speeds to feel "real"
    statusIntervalRef.current = window.setInterval(() => {
        statusIdx = Math.min(statusIdx + 1, statusSequence.length - 1);
        setStatus(statusSequence[statusIdx]);
    }, 1200 + Math.random() * 800);

    let base64Image = undefined;
    if (image) {
      const reader = new FileReader();
      base64Image = await new Promise<string>((resolve) => {
        reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(image);
      });
    }

    try {
      const analysis = await analyzeClaim(claim, base64Image);

      const newCheck: FactCheckResult = {
        ...analysis,
        id: Date.now().toString(),
        timestamp: Date.now(),
        author: user ? user.name : 'Network Auditor'
      };

      submitCheck(newCheck);
      setResult(newCheck);
    } catch (err) {
      console.error(err);
      alert("Analysis Engine Error: The node failed to respond. This usually happens if the link is unreachable or the search grounding quota is exceeded.");
    } finally {
      setIsAnalyzing(false);
      setStatus('');
      if (statusIntervalRef.current) clearInterval(statusIntervalRef.current);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <div className="text-center mb-10">
        <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-primary-900/30 text-primary-400 rounded-full border border-primary-800 mb-4 animate-pulse">
            <Globe className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Live Link Forensic Active</span>
        </div>
        <h1 className="text-4xl md:text-6xl font-black text-white mb-4 tracking-tighter">
            CITIZEN <span className="text-primary-500 italic">VERIFY</span>
        </h1>
        <p className="text-slate-400 text-lg max-w-2xl mx-auto font-medium">
          Paste links to Reels, X Posts, or TikToks. Our AI will track the source, check for manipulation, and find reputable external reporting.
        </p>
      </div>

      <div className="grid grid-cols-1 gap-8">
          <div className="bg-slate-900/50 backdrop-blur-xl rounded-3xl border border-slate-800 shadow-2xl overflow-hidden">
             <div className="p-8">
                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="relative">
                        <label className="flex items-center gap-2 text-[10px] font-black text-slate-500 mb-3 uppercase tracking-[0.2em]">
                            <LinkIcon className="w-3 h-3 text-primary-500" /> Viral URL or Text Claim
                        </label>
                        <textarea
                            value={claim}
                            onChange={(e) => setClaim(e.target.value)}
                            placeholder="Paste Instagram Reel link, X post URL, or a text statement..."
                            className="w-full h-32 px-5 py-4 bg-black border border-slate-800 text-white rounded-2xl focus:ring-2 focus:ring-primary-600 outline-none transition-all resize-none text-base font-medium placeholder-slate-700 shadow-inner"
                        />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div 
                            onClick={() => fileInputRef.current?.click()}
                            className={`border-2 border-dashed rounded-2xl p-6 text-center cursor-pointer transition-all ${previewUrl ? 'border-primary-600 bg-primary-950/20' : 'border-slate-800 hover:border-primary-600 hover:bg-black'}`}
                        >
                            {previewUrl ? (
                                <img src={previewUrl} alt="Preview" className="max-h-32 mx-auto rounded-lg shadow-xl" />
