import React, { useState, useRef, useEffect } from 'react';
import { Loader2, Search, Image as ImageIcon, ExternalLink, ShieldCheck, Cpu, Globe, Link as LinkIcon, Fingerprint, Database, Zap, Compass, ShieldAlert, AlertCircle, FileCheck, X, FileWarning } from 'lucide-react';
import { analyzeClaim } from '../services/geminiService';
import { FactCheckResult } from '../types';
import { VerdictBadge } from '../components/VerdictBadge';
import { useAuth } from '../context/AuthContext';

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'image/webp'];

export const Verify: React.FC = () => {
  const [claim, setClaim] = useState('');
  const [image, setImage] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [status, setStatus] = useState('');
  const [result, setResult] = useState<any>(null);
  const [fileError, setFileError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const statusIntervalRef = useRef<number | null>(null);
  const { user, submitCheck } = useAuth();

  useEffect(() => {
    return () => { 
      if (previewUrl?.startsWith('blob:')) URL.revokeObjectURL(previewUrl); 
      if (statusIntervalRef.current) clearInterval(statusIntervalRef.current);
    };
  }, [previewUrl]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFileError(null);
    const file = e.target.files?.[0];

    if (!file) return;

    // Validation: Type Check
    if (!ALLOWED_TYPES.includes(file.type)) {
      setFileError('Invalid format. Please upload JPG, PNG, or WEBP.');
      setImage(null);
      if (previewUrl) URL.revokeObjectURL(previewUrl);
      setPreviewUrl(null);
      return;
    }

    // Validation: Size Check
    if (file.size > MAX_FILE_SIZE) {
      setFileError(`Image too large. Limit is ${MAX_FILE_SIZE / (1024 * 1024)}MB.`);
      setImage(null);
      if (previewUrl) URL.revokeObjectURL(previewUrl);
      setPreviewUrl(null);
      return;
    }

    setImage(file);
    setPreviewUrl(URL.createObjectURL(file));
  };

  const clearImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setImage(null);
    if (previewUrl) URL.revokeObjectURL(previewUrl);
    setPreviewUrl(null);
    setFileError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    // Do not submit if there is an active file error or if inputs are empty
    if (fileError || (!claim && !image)) return;

    setIsAnalyzing(true);
    setResult(null);
    setFileError(null);

    const isUrl = claim.trim().startsWith('http');
    const isMajorOutlet = claim.toLowerCase().includes('bbc') || 
                           claim.toLowerCase().includes('cnn') || 
                           claim.toLowerCase().includes('reuters') || 
                           claim.toLowerCase().includes('aljazeera') ||
                           claim.toLowerCase().includes('nytimes') ||
                           claim.toLowerCase().includes('theguardian');

    const statusSequence = isMajorOutlet ? [
        "Major Outlet Detected: Linking Official Mirror...",
        "Identifying Publisher Digital Fingerprint...",
        "Scanning Official News Website Databases...",
        "Bypassing Social Media Auth Gate...",
        "Cross-Reading Website Article Context...",
        "Gemini 3 Deep Reasoning Active...",
        "Syncing Official Narrative with Social Claims...",
        "Finalizing Verification Certificate..."
    ] : isUrl ? [
        "Analyzing Social Media Breadcrumbs...",
        "Querying Authenticate News Databases...",
        "Cross-Referencing Global News Nodes...",
        "Scanning Fact-Check Repositories...",
        "Detecting Reporting Discrepancies...",
        "Finalizing Verification Audit..."
    ] : [
        "Initializing Forensic Handshake...",
        "Querying Verified News Citations...",
        "Gemini 3 Deep Reasoning Active...",
        "Finalizing Intelligence Report..."
    ];

    let statusIdx = 0;
    setStatus(statusSequence[0]);

    statusIntervalRef.current = window.setInterval(() => {
        statusIdx = Math.min(statusIdx + 1, statusSequence.length - 1);
        setStatus(statusSequence[statusIdx]);
    }, 1800);

    let base64Image = undefined;
    if (image) {
      try {
        const reader = new FileReader();
        base64Image = await new Promise<string>((resolve, reject) => {
          reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
          reader.onerror = reject;
          reader.readAsDataURL(image);
        });
      } catch (err) {
        setFileError("Failed to process image payload.");
        setIsAnalyzing(false);
        return;
      }
    }

    try {
      const analysis = await analyzeClaim(claim, base64Image);
      const newCheck: FactCheckResult = {
        ...analysis,
        id: Date.now().toString(),
        timestamp: Date.now(),
        author: user ? user.name : 'Network Auditor'
      };
      submitCheck(newCheck);
      setResult(analysis);
    } catch (err) {
      console.error(err);
      setFileError("Verification Node Offline: Could not complete mirroring process.");
    } finally {
      setIsAnalyzing(false);
      setStatus('');
      if (statusIntervalRef.current) clearInterval(statusIntervalRef.current);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <div className="text-center mb-10">
        <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-primary-900/30 text-primary-400 rounded-full border border-primary-800 mb-4 animate-pulse">
            <Globe className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Article Mirroring Active</span>
        </div>
        <h1 className="text-4xl md:text-6xl font-black text-white mb-4 tracking-tighter uppercase italic">
            Citizen <span className="text-primary-500">Forensics</span>
        </h1>
        <p className="text-slate-400 text-lg max-w-2xl mx-auto font-medium leading-relaxed">
          Paste a social link. Our AI mirrors the post by finding and "reading" the matching article on the publisher's official website.
        </p>
      </div>

      <div className="grid grid-cols-1 gap-8">
          <div className="bg-slate-900/50 backdrop-blur-xl rounded-3xl border border-slate-800 shadow-2xl overflow-hidden">
             <div className="p-8">
                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="relative">
                        <label className="flex items-center gap-2 text-[10px] font-black text-slate-500 mb-3 uppercase tracking-[0.2em]">
                            <LinkIcon className="w-3 h-3 text-primary-500" /> Viral Source URL
                        </label>
                        <textarea
                            value={claim}
                            onChange={(e) => setClaim(e.target.value)}
                            placeholder="Paste Instagram Reel, TikTok, or News URL for forensic auditing..."
                            className="w-full h-32 px-5 py-4 bg-black border border-slate-800 text-white rounded-2xl focus:ring-2 focus:ring-primary-600 outline-none transition-all resize-none text-base font-medium placeholder-slate-700 shadow-inner"
                        />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div 
                            onClick={() => fileInputRef.current?.click()}
                            className={`relative border-2 border-dashed rounded-2xl p-6 text-center cursor-pointer transition-all group ${previewUrl ? 'border-primary-600 bg-primary-950/20' : fileError ? 'border-red-600 bg-red-950/20' : 'border-slate-800 hover:border-primary-600 hover:bg-black'}`}
                        >
                            {previewUrl ? (
                                <div className="relative">
                                    <img src={previewUrl} alt="Preview" className="max-h-32 mx-auto rounded-lg shadow-xl" />
                                    <button 
                                        onClick={clearImage}
                                        className="absolute -top-3 -right-3 bg-red-600 text-white p-1.5 rounded-full hover:bg-red-500 transition-all shadow-lg hover:scale-110"
                                        title="Remove Image"
                                    >
                                        <X className="w-4 h-4" />
                                    </button>
                                </div>
                            ) : (
                                <div className="space-y-2">
                                    {fileError ? (
                                        <FileWarning className="w-8 h-8 text-red-500 mx-auto animate-bounce" />
                                    ) : (
                                        <ImageIcon className="w-8 h-8 text-slate-700 mx-auto group-hover:text-primary-500 transition-colors" />
                                    )}
                                    <p className={`text-[10px] font-bold uppercase ${fileError ? 'text-red-400' : 'text-slate-500'}`}>
                                        {fileError ? 'Validation Error' : 'Evidence Snapshot'}
                                    </p>
                                    <p className="text-[9px] text-slate-600">JPG, PNG, WEBP (Max 5MB)</p>
                                </div>
                            )}
                            <input 
                                type="file" 
                                ref={fileInputRef} 
                                className="hidden" 
                                accept="image/jpeg,image/png,image/webp" 
                                onChange={handleImageChange} 
                            />

                            {fileError && (
                                <div className="mt-3 text-red-500 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 bg-red-950/30 py-2 rounded-lg border border-red-900/30">
                                    <AlertCircle className="w-3 h-3" /> {fileError}
                                </div>
                            )}
                        </div>

                        <button
                            type="submit"
                            disabled={isAnalyzing || !!fileError || (!claim && !image)}
                            className="h-full py-4 rounded-2xl font-black text-xl bg-primary-600 text-white hover:bg-primary-500 disabled:opacity-50 disabled:cursor-not-allowed flex flex-col items-center justify-center gap-2 transition-all shadow-lg shadow-primary-900/30 overflow-hidden relative active:scale-95"
                        >
                            {isAnalyzing ? (
                                <>
                                    <Loader2 className="animate-spin w-8 h-8 mb-2" />
                                    <span className="text-[10px] font-mono uppercase tracking-[0.2em] animate-pulse text-white px-4 text-center leading-tight">{status}</span>
                                </>
                            ) : (
                                <>
                                    <ShieldCheck className="w-8 h-8" />
                                    <span>RUN FORENSIC SCAN</span>
                                </>
                            )}
                        </button>
                    </div>
                </form>
             </div>
          </div>

          {result && (
            <div className="animate-fade-in-up space-y-6">
               {/* Mirror Found Alert */}
               {result.mirrorFound && (
                   <div className="bg-green-600/20 rounded-2xl p-6 border border-green-500/50 flex gap-5 items-start">
                        <div className="bg-green-600 p-2 rounded-xl shrink-0">
                            <FileCheck className="w-6 h-6 text-white" />
                        </div>
                        <div>
                            <h3 className="text-green-400 font-black uppercase tracking-tighter text-lg">Official Mirror Found</h3>
                            <p className="text-green-50/70 font-medium text-sm leading-relaxed mt-1">
                                Verified: Our AI located the corresponding article on the publisher's official domain. This social post is a faithful mirror of authorized reporting.
                            </p>
                        </div>
                   </div>
               )}

               {result.isDigitalGhost && !result.mirrorFound && (
                   <div className="bg-red-600 rounded-2xl p-6 border border-red-500 shadow-lg shadow-red-900/20 flex gap-5 items-start">
                        <div className="bg-white p-2 rounded-xl shrink-0">
                            <ShieldAlert className="w-6 h-6 text-red-600" />
                        </div>
                        <div>
                            <h3 className="text-white font-black uppercase tracking-tighter text-lg">Digital Ghost Detected</h3>
                            <p className="text-red-50 font-medium text-sm leading-relaxed mt-1">
                                Alert: No matching coverage exists in authenticate news databases. Viral posts from purported news accounts with zero website footprint are high-risk fabrications.
                            </p>
                        </div>
                   </div>
               )}

               <div className="bg-slate-900 rounded-3xl border border-slate-800 shadow-2xl overflow-hidden">
                   <div className="p-8">
                       <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 border-b border-slate-800 pb-8">
                           <div className="space-y-4">
                               <VerdictBadge verdict={result.verdict} className="text-xl px-8 py-3" />
                               <h2 className="text-3xl font-black text-white leading-tight">{result.headline}</h2>
                           </div>
                           <div className="bg-black border border-slate-800 p-6 rounded-2xl text-center min-w-[140px]">
                               <div className="text-[10px] font-black text-slate-500 uppercase mb-2">Confidence</div>
                               <div className="text-4xl font-black text-primary-500">{result.confidenceScore}%</div>
                           </div>
                       </div>

                       <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
                           <div className="md:col-span-8 space-y-8">
                               <div>
                                   <h4 className="text-[10px] font-black text-primary-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                                       <Cpu className="w-3 h-3" /> Forensic Analysis
                                   </h4>
                                   <p className="text-slate-300 leading-relaxed text-lg font-medium">{result.explanation}</p>
                               </div>

                               {result.searchQueries?.length > 0 && (
                                   <div className="bg-primary-950/20 p-6 rounded-2xl border border-primary-900/30">
                                       <h4 className="text-[10px] font-black text-primary-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                                           <Compass className="w-3 h-3" /> Mirroring Path
                                       </h4>
                                       <div className="flex flex-wrap gap-2">
                                           {result.searchQueries.map((q: string, i: number) => (
                                               <span key={i} className="px-3 py-1 bg-black border border-slate-800 rounded-full text-[10px] font-mono text-slate-500 italic">"{q}"</span>
                                           ))}
                                       </div>
                                   </div>
                               )}
                           </div>

                           <div className="md:col-span-4 space-y-6">
                               <div className="bg-slate-950 p-6 rounded-2xl border border-slate-800">
                                   <h4 className="text-[10px] font-black text-slate-500 uppercase mb-4 tracking-widest flex items-center gap-2">
                                       <Database className="w-3 h-3" /> Verified Citations
                                   </h4>
                                   <div className="space-y-3">
                                       {result.sources?.map((s: any, i: number) => (
                                           <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="flex items-center justify-between p-3 bg-slate-900 border border-slate-800 hover:border-primary-500 rounded-xl transition-all group">
                                               <span className="text-[10px] font-bold text-slate-300 truncate pr-2">{s.title}</span>
                                               <ExternalLink className="w-3 h-3 text-slate-600 group-hover:text-primary-500 shrink-0" />
                                           </a>
                                       ))}
                                       {!result.sources?.length && (
                                           <div className="p-4 bg-red-900/10 border border-red-900/20 rounded-xl">
