export const Home: React.FC = () => {
  const [localChecks, setLocalChecks] = useState<FactCheckResult[]>(() => db.content.getFeed());
  const [trendingChecks, setTrendingChecks] = useState<FactCheckResult[]>(() => db.content.getTrending());
  const [loadingTrending, setLoadingTrending] = useState(() => db.content.getTrending().length === 0);
  const [tickerItems, setTickerItems] = useState<TickerItem[]>([]);
  const [recentActivities, setRecentActivities] = useState<ActivityType[]>([]);
  const [lastTickerUpdate, setLastTickerUpdate] = useState<Date>(new Date());

  const { user, castVote, activeUsersCount, getRecentActivities } = useAuth();
  const { language, t } = useLanguage();

  const langName = LANGUAGES.find(l => l.code === language)?.name || 'English';

  const loadTicker = async () => {
    const news = await fetchRealTopNews(langName);
    if (news?.length) {
      setTickerItems(news);
      setLastTickerUpdate(new Date());
    }
  };

  useEffect(() => {
    loadContent(db.content.isCacheStale());
    loadTicker();
    setRecentActivities(getRecentActivities());

    const tickerInterval = setInterval(loadTicker, 60000);
    const activityInterval = setInterval(() => setRecentActivities(getRecentActivities()), 5000);

    return () => {
      clearInterval(tickerInterval);
      clearInterval(activityInterval);
    };
  }, [language]); // Reload news when language changes

  const loadContent = async (force = false) => {
    if (db.content.getTrending().length === 0) setLoadingTrending(true);
    setLocalChecks(db.content.getFeed());
    try {
        const trending = await fetchTrendingDebunks(langName, force);
        setTrendingChecks(trending);
    } catch (e) { console.error(e); } finally { setLoadingTrending(false); }
  };

  const handleVote = (id: string, opt: 'trueVotes' | 'falseVotes' | 'misleadingVotes') => {
    castVote(id, opt);
    const upd = (l: FactCheckResult[]) => l.map(i => i.id === id ? { ...i, communityPoll: { ...i.communityPoll, [opt]: i.communityPoll[opt]+1, total: i.communityPoll.total+1 } } : i);
    setTrendingChecks(upd); setLocalChecks(upd);
  };

  const feedItems = useMemo(() => {
    return [...localChecks, ...trendingChecks].sort((a, b) => b.timestamp - a.timestamp);
