                        <div className="flex items-center gap-1.5 bg-slate-800/50 px-2 py-0.5 rounded">
                           {item.verdict === 'TRUE' ? <CheckCircle2 className="w-3 h-3 text-green-500" /> : <XCircle className="w-3 h-3 text-red-500" />}
                           <span className="text-[9px] font-bold text-slate-400 uppercase">OK</span>
                        </div>
                     </div>
                 ))}
             </div>
         </div>

         <div className="hidden lg:flex items-center gap-2 px-4 border-l border-slate-800 bg-slate-900 z-10 text-slate-500 text-[10px] font-bold uppercase tracking-widest">
            <Clock className="w-3 h-3" />
            {lastTickerUpdate.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-8 space-y-8">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-3xl font-black text-white tracking-tighter uppercase">{t('nav_feed')}</h2>
                    <p className="text-slate-500 text-sm font-medium">FactPulse Stream</p>
