                <button onClick={() => loadContent(true)} className="p-3 bg-slate-900 border border-slate-800 rounded-xl hover:bg-slate-800 transition-all">
                    <RefreshCw className={`w-5 h-5 text-primary-400 ${loadingTrending ? 'animate-spin' : ''}`} />
                </button>
            </div>

            {loadingTrending && !feedItems.length ? (
                <div className="grid gap-6">
                    {[1, 2].map(i => <div key={i} className="bg-slate-900/50 rounded-2xl h-80 animate-pulse border border-slate-800"></div>)}
                </div>
            ) : (
                feedItems.map((item) => (
                    <div key={item.id} className="bg-slate-900/40 rounded-3xl overflow-hidden border border-slate-800 hover:border-primary-900/50 transition-all group">
