                                </div>
                                <div className="flex-1 flex flex-col justify-between">
                                    <div>
                                        <div className="flex items-center gap-3 mb-4">
                                            <div className="h-8 w-8 bg-primary-900/30 text-primary-500 rounded-lg flex items-center justify-center text-xs font-black border border-primary-800">{item.author[0]}</div>
                                            <div className="text-xs">
