                                    <div className="flex items-center justify-between pt-6 border-t border-slate-800/50">
                                        <div className="flex-1"><PollWidget checkId={item.id} stats={item.communityPoll} onVote={handleVote} userVotedOption={user?.votes?.[item.id]} /></div>
                                        <div className="flex items-center gap-4 ml-8">
                                            <Link to="/verify" className="text-slate-500 hover:text-white transition-colors"><Eye className="w-5 h-5" /></Link>
                                            <button className="text-slate-500 hover:text-primary-500"><Share2 className="w-5 h-5" /></button>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                ))
            )}
        </div>

        <div className="lg:col-span-4 space-y-8">
             <div className="bg-gradient-to-br from-primary-900/20 to-slate-950 p-8 rounded-3xl border border-primary-900/30 shadow-2xl">
                 <h3 className="text-xl font-black text-white mb-2 uppercase italic tracking-tighter">{t('hero_subtitle')}</h3>
                 <p className="text-slate-400 text-sm leading-relaxed mb-6">{t('hero_desc')}</p>
                 <div className="bg-slate-900/50 rounded-2xl p-4 border border-slate-800 mb-6">
                    <div className="flex justify-between text-xs font-bold mb-2">
                        <span className="text-slate-500 uppercase">{t('online_count')}</span>
                        <span className="text-green-500">{activeUsersCount.toLocaleString()}</span>
                    </div>
                    <div className="h-1 bg-slate-800 rounded-full overflow-hidden">
                        <div className="h-full bg-green-500 transition-all duration-1000" style={{ width: `${(activeUsersCount/3000)*100}%` }}></div>
                    </div>
                 </div>
                 <Link to="/verify" className="block w-full py-4 bg-primary-600 hover:bg-primary-500 text-white font-black text-center rounded-2xl transition-all shadow-xl shadow-primary-900/30">
                  {t('btn_scan')}
                 </Link>
