             <div className="bg-slate-900/30 rounded-3xl p-6 border border-slate-800">
                 <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center gap-2">
                    <MessageSquare className="w-3 h-3 text-primary-500" /> Activity
                 </h4>
                 <div className="space-y-5">
                     {recentActivities.map((a) => (
                         <div key={a.id} className="flex gap-4 animate-fade-in">
                             <div className="w-1.5 h-1.5 rounded-full bg-primary-500 mt-2 shrink-0"></div>
                             <div>
                                 <p className="text-xs text-slate-300"><span className="text-white font-bold">{a.userName}</span> {a.action}</p>
