  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Loader2, Search, Image as ImageIcon, ExternalLink, ShieldCheck, Cpu, Globe, Link as LinkIcon, Fingerprint, Database, Zap, Compass, ShieldAlert, AlertCircle, FileCheck, X, FileWarning } from 'lucide-react';
import { analyzeClaim } from '../services/geminiService';
import { FactCheckResult } from '../types';
import { VerdictBadge } from '../components/VerdictBadge';
import { useAuth } from '../context/AuthContext';
import { useLanguage, LANGUAGES } from '../context/LanguageContext';

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'image/webp'];

export const Verify: React.FC = () => {
  const [claim, setClaim] = useState('');
  const [image, setImage] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [status, setStatus] = useState('');
  const [result, setResult] = useState<any>(null);
  const [fileError, setFileError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const statusIntervalRef = useRef<number | null>(null);
  const { user, submitCheck } = useAuth();
  const { t, language } = useLanguage();

  const langName = LANGUAGES.find(l => l.code === language)?.name || 'English';

  useEffect(() => {
    return () => { 
      if (previewUrl?.startsWith('blob:')) URL.revokeObjectURL(previewUrl); 
      if (statusIntervalRef.current) clearInterval(statusIntervalRef.current);
    };
  }, [previewUrl]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFileError(null);
    const file = e.target.files?.[0];
    if (!file) return;
    if (!ALLOWED_TYPES.includes(file.type)) {
      setFileError('Invalid format. JPG, PNG, WEBP only.');
      return;
    }
    if (file.size > MAX_FILE_SIZE) {
      setFileError('File too large (Max 5MB).');
      return;
    }
    setImage(file);
    setPreviewUrl(URL.createObjectURL(file));
  };

  const clearImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setImage(null);
    if (previewUrl) URL.revokeObjectURL(previewUrl);
    setPreviewUrl(null);
    setFileError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (fileError || (!claim && !image)) return;

    setIsAnalyzing(true);
    setResult(null);
    setFileError(null);

    setStatus('Initializing forensic nodes...');
    statusIntervalRef.current = window.setInterval(() => {
      setStatus(prev => prev === 'Initializing forensic nodes...' ? 'Querying official databases...' : 'Analyzing content mirror...');
    }, 2000);

    let base64Image = undefined;
    if (image) {
      const reader = new FileReader();
      base64Image = await new Promise<string>((resolve) => {
        reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(image);
      });
    }

    try {
      const analysis = await analyzeClaim(claim, langName, base64Image);
      const newCheck: FactCheckResult = {
        ...analysis,
        id: Date.now().toString(),
        timestamp: Date.now(),
        author: user ? user.name : 'Network Auditor'
      };
      submitCheck(newCheck);
      setResult(analysis);
    } catch (err) {
      console.error(err);
      setFileError("Verification failed. Please check connection.");
    } finally {
      setIsAnalyzing(false);
      setStatus('');
      if (statusIntervalRef.current) clearInterval(statusIntervalRef.current);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <div className="text-center mb-10">
        <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-primary-900/30 text-primary-400 rounded-full border border-primary-800 mb-4 animate-pulse">
            <Globe className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">{t('nav_verify')}</span>
        </div>
        <h1 className="text-4xl md:text-6xl font-black text-white mb-4 tracking-tighter uppercase italic">
            {t('hero_title')} <span className="text-primary-500">{t('hero_subtitle')}</span>
        </h1>
        <p className="text-slate-400 text-lg max-w-2xl mx-auto font-medium leading-relaxed">
          {t('hero_desc')}
        </p>
      </div>

      <div className="grid grid-cols-1 gap-8">
          <div className="bg-slate-900/50 backdrop-blur-xl rounded-3xl border border-slate-800 shadow-2xl overflow-hidden">
             <div className="p-8">
                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="relative">
                        <label className="flex items-center gap-2 text-[10px] font-black text-slate-500 mb-3 uppercase tracking-[0.2em]">
                            <LinkIcon className="w-3 h-3 text-primary-500" /> {t('nav_verify')}
                        </label>
                        <textarea
                            value={claim}
                            onChange={(e) => setClaim(e.target.value)}
                            placeholder={t('input_placeholder')}
                            className="w-full h-32 px-5 py-4 bg-black border border-slate-800 text-white rounded-2xl focus:ring-2 focus:ring-primary-600 outline-none transition-all resize-none text-base font-medium placeholder-slate-700 shadow-inner"
                        />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div 
                            onClick={() => fileInputRef.current?.click()}
                            className={`relative border-2 border-dashed rounded-2xl p-6 text-center cursor-pointer transition-all ${previewUrl ? 'border-primary-600' : 'border-slate-800'}`}
                        >
                            {previewUrl ? (
                                <div className="relative">
                                    <img src={previewUrl} alt="Preview" className="max-h-32 mx-auto rounded-lg shadow-xl" />
                                    <button onClick={clearImage} className="absolute -top-3 -right-3 bg-red-600 p-1.5 rounded-full"><X className="w-4 h-4 text-white" /></button>
                                </div>
                            ) : (
                                <div className="space-y-2">
                                    <ImageIcon className="w-8 h-8 text-slate-700 mx-auto" />
                                    <p className="text-[10px] font-bold text-slate-500 uppercase">Snapshot</p>
                                </div>
                            )}
                            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageChange} />
                        </div>

                        <button
                            type="submit"
                            disabled={isAnalyzing || !!fileError || (!claim && !image)}
                            className="h-full py-4 rounded-2xl font-black text-xl bg-primary-600 text-white hover:bg-primary-500 disabled:opacity-50 transition-all flex flex-col items-center justify-center gap-2"
                        >
                            {isAnalyzing ? (
                                <><Loader2 className="animate-spin w-8 h-8 mb-2" /><span className="text-[10px] font-mono uppercase">{status}</span></>
                            ) : (
                                <><ShieldCheck className="w-8 h-8" /><span>{t('btn_scan')}</span></>
                            )}
                        </button>
                    </div>
                </form>
             </div>
          </div>

          {result && (
            <div className="animate-fade-in-up space-y-6">
               {result.mirrorFound && (
                   <div className="bg-green-600/20 rounded-2xl p-6 border border-green-500/50 flex gap-5 items-start">
                        <FileCheck className="w-6 h-6 text-green-400 shrink-0" />
                        <div><h3 className="text-green-400 font-black uppercase text-lg">{t('label_mirror')}</h3></div>
                   </div>
               )}

               <div className="bg-slate-900 rounded-3xl border border-slate-800 shadow-2xl overflow-hidden p-8">
                   <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 border-b border-slate-800 pb-8">
                       <div className="space-y-4">
                           <VerdictBadge verdict={result.verdict} className="text-xl" />
                           <h2 className="text-3xl font-black text-white leading-tight">{result.headline}</h2>
                       </div>
                       <div className="bg-black border border-slate-800 p-6 rounded-2xl text-center min-w-[140px]">
                           <div className="text-[10px] font-black text-slate-500 uppercase mb-2">{t('label_confidence')}</div>
                           <div className="text-4xl font-black text-primary-500">{result.confidenceScore}%</div>
                       </div>
                   </div>

                   <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
                       <div className="md:col-span-8 space-y-8">
                           <div>
                               <h4 className="text-[10px] font-black text-primary-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                                   <Cpu className="w-3 h-3" /> {t('label_analysis')}
                               </h4>
                               <p className="text-slate-300 leading-relaxed text-lg font-medium">{result.explanation}</p>
                           </div>
                       </div>

                       <div className="md:col-span-4">
                           <div className="bg-slate-950 p-6 rounded-2xl border border-slate-800">
                               <h4 className="text-[10px] font-black text-slate-500 uppercase mb-4 tracking-widest">{t('label_sources')}</h4>
                               <div className="space-y-3">
                                   {result.sources?.map((s: any, i: number) => (
                                       <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="flex items-center justify-between p-3 bg-slate-900 border border-slate-800 rounded-xl">
                                           <span className="text-[10px] font-bold text-slate-300 truncate">{s.title}</span>
                                           <ExternalLink className="w-3 h-3 text-slate-600" />
                                       </a>
                                   ))}
                               </div>
                           </div>
                       </div>
                   </div>
               </div>
            </div>
          )}
      </div>
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { User, FactCheckResult, Activity } from '../types';
import { fetchTrendingDebunks } from '../services/geminiService';
