const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const normalizeVerdict = (verdict: string): VerdictType => {
  const v = (verdict || "").toUpperCase().trim();
  if (v.includes("TRUE") || v.includes("AUTHENTIC") || v.includes("FACT")) return VerdictType.TRUE;
  if (v.includes("FALSE") || v.includes("FAKE") || v.includes("FABRICATED")) return VerdictType.FALSE;
  if (v.includes("MISLEADING") || v.includes("CONTEXT") || v.includes("PARTIAL")) return VerdictType.MISLEADING;
  return VerdictType.UNVERIFIED;
};

const cleanJsonString = (text: string): string => {
  if (!text) return "";
  const firstBrace = text.indexOf('{');
  const firstBracket = text.indexOf('[');
  let start = -1, end = -1, stack = 0, charOpen = '', charClose = '';

  if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
    start = firstBrace; charOpen = '{'; charClose = '}';
  } else if (firstBracket !== -1) {
    start = firstBracket; charOpen = '['; charClose = ']';
  }

  if (start === -1) return text.trim();
  for (let i = start; i < text.length; i++) {
    if (text[i] === charOpen) stack++;
    if (text[i] === charClose) {
      stack--;
      if (stack === 0) { end = i; break; }
    }
  }
  return (start !== -1 && end !== -1) ? text.substring(start, end + 1) : text.trim();
};

const getNewsImage = (keyword: string): string => {
  const seed = encodeURIComponent(keyword.substring(0, 15));
  return `https://picsum.photos/seed/${seed}/800/450`;
};

export const fetchRealTopNews = async (lang: string = 'English'): Promise<TickerItem[]> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: [{ 
              parts: [{ 
                text: `Search for the 8 most recent breaking news headlines. Return JSON array in ${lang}: [{"headline":"...", "verdict":"TRUE"|"FALSE", "source":"..."}]` 
              }] 
            }],
            config: { 
              tools: [{ googleSearch: {} }], 
              temperature: 0.2,
              systemInstruction: `You are a real-time news service. Provide punchy headlines in ${lang}.`
            }
        });

        const data = JSON.parse(cleanJsonString(response.text || "[]"));
        if (Array.isArray(data) && data.length > 0) {
            const normalized = data.map((item: any) => ({
                ...item,
                verdict: normalizeVerdict(item.verdict) === VerdictType.TRUE ? 'TRUE' : 'FALSE'
            }));
            db.analytics.saveTicker(normalized);
            return normalized;
        }
    } catch (e) { console.error("Ticker fetch error:", e); }
    return db.analytics.getTicker();
};

export const analyzeClaim = async (text: string, lang: string = 'English', imageBase64?: string): Promise<any> => {
  const startTime = Date.now();
  const parts: any[] = [];

  if (imageBase64) {
    parts.push({ inlineData: { data: imageBase64, mimeType: "image/jpeg" } });
  }

  const prompt = `
    TASK: Verify the following claim for authenticity/misinformation.
    INPUT: "${text}"
    TARGET LANGUAGE: ${lang}

    INSTRUCTIONS:
    1. Search for reputable news coverage of this claim.
    2. Determine if it is TRUE, FALSE, or MISLEADING.
    3. Return all response fields in ${lang}.

    RETURN JSON ONLY:
    {
      "verdict": "TRUE" | "FALSE" | "MISLEADING" | "UNVERIFIED",
      "headline": "A short descriptive title in ${lang}",
      "summary": "Explanation of your findings in ${lang}.",
      "keyPoints": ["Fact 1 in ${lang}", "Fact 2 in ${lang}"],
      "confidenceScore": 0-100,
      "bias": "NEUTRAL" | "POLARIZING",
      "searchQueries": ["query used 1", "query used 2"]
    }
  `;

  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts }],
      config: {
        systemInstruction: `You are a Fact-Checking Expert. Return all text fields in ${lang}.`,
        tools: [{ googleSearch: {} }],
        temperature: 0,
        thinkingConfig: { thinkingBudget: 15000 }
      }
    });

    const json = JSON.parse(cleanJsonString(response.text || "{}"));
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources: Source[] = Array.from(new Map<string, Source>(
      chunks.filter((c: any) => c.web?.uri).map((c: any) => [c.web.uri, { title: c.web.title || "Official Source", uri: c.web.uri }])
    ).values());

    return {
      claim: text || "Verification Result",
      verdict: normalizeVerdict(json.verdict),
      explanation: json.summary || "No data available.",
      headline: json.headline || "Detection Result",
      keyPoints: json.keyPoints || [],
      confidenceScore: json.confidenceScore || 50,
      biasRating: json.bias || 'NEUTRAL',
      sources: sources,
      imageUrl: imageBase64 ? `data:image/jpeg;base64,${imageBase64}` : undefined,
      communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
      analysisTime: Date.now() - startTime,
      searchQueries: json.searchQueries || []
    };
  } catch (error) {
    console.error("Analysis Error:", error);
    throw error;
  }
};

export const fetchTrendingDebunks = async (lang: string = 'English', forceRefresh = false): Promise<FactCheckResult[]> => {
    if (!forceRefresh && !db.content.isCacheStale()) {
      const cached = db.content.getTrending();
      if (cached.length > 0) return cached;
    }
    try {
       const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [{ parts: [{ text: `List 4 viral social media claims today. Return JSON array in ${lang}: [{headline, summary, verdict, sourceName, bias}]` }] }],
        config: { tools: [{ googleSearch: {} }], temperature: 0.5 }
      });
      const data = JSON.parse(cleanJsonString(response.text || "[]"));
      return data.map((item: any, i: number) => ({
          id: `trend-${Date.now()}-${i}`,
          claim: item.headline,
          verdict: normalizeVerdict(item.verdict),
          explanation: item.summary,
          headline: item.headline,
          keyPoints: ["AI search grounded verification"],
          sources: [{ title: item.sourceName || "Source", uri: "#" }],
          timestamp: Date.now(),
          confidenceScore: 85,
          biasRating: item.bias || 'NEUTRAL',
          communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
          author: "Truth Engine",
          imageUrl: getNewsImage(item.headline)
      }));
    } catch (e) { return db.content.getTrending(); }
};

