const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
const ALLOWED_TYPES = ['image/jpeg', 'image/png']; // Restricted as requested

export const Verify: React.FC = () => {
  const [claim, setClaim] = useState('');
  const [image, setImage] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [status, setStatus] = useState('');
  const [result, setResult] = useState<any>(null);
  const [fileError, setFileError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const statusIntervalRef = useRef<number | null>(null);
  const { user, submitCheck } = useAuth();
  const { t, language } = useLanguage();

  const langName = LANGUAGES.find(l => l.code === language)?.name || 'English';

  useEffect(() => {
    return () => { 
      if (previewUrl?.startsWith('blob:')) URL.revokeObjectURL(previewUrl); 
      if (statusIntervalRef.current) clearInterval(statusIntervalRef.current);
    };
  }, [previewUrl]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFileError(null);
    const file = e.target.files?.[0];
    if (!file) return;

    // Type Validation
    if (!ALLOWED_TYPES.includes(file.type)) {
      setFileError('Unsupported file type. Please upload JPG or PNG.');
      setImage(null);
      if (previewUrl) URL.revokeObjectURL(previewUrl);
      setPreviewUrl(null);
      return;
    }

    // Size Validation
    if (file.size > MAX_FILE_SIZE) {
      setFileError('File size exceeds 5MB limit.');
      setImage(null);
      if (previewUrl) URL.revokeObjectURL(previewUrl);
      setPreviewUrl(null);
      return;
    }

    setImage(file);
    setPreviewUrl(URL.createObjectURL(file));
  };

  const clearImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setImage(null);
    if (previewUrl) URL.revokeObjectURL(previewUrl);
    setPreviewUrl(null);
    setFileError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (fileError || (!claim && !image)) return;

    setIsAnalyzing(true);
    setResult(null);

    setStatus('Searching for evidence...');
    statusIntervalRef.current = window.setInterval(() => {
      setStatus(prev => prev === 'Searching for evidence...' ? 'Cross-referencing sources...' : 'Generating AI assessment...');
    }, 2000);

    let base64Image = undefined;
    if (image) {
      const reader = new FileReader();
      base64Image = await new Promise<string>((resolve) => {
        reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(image);
      });
    }

    try {
      const analysis = await analyzeClaim(claim, langName, base64Image);
      const newCheck: FactCheckResult = {
        ...analysis,
        id: Date.now().toString(),
        timestamp: Date.now(),
        author: user ? user.name : 'System Node'
      };
      submitCheck(newCheck);
      setResult(analysis);
    } catch (err) {
      console.error(err);
      setFileError("Detection failed. Please check your network connection.");
    } finally {
