import { User, FactCheckResult, TickerItem, Activity } from '../types';

/**
 * DATABASE SCHEMA VERSION 6.0
 * Multi-Language Cache Support
 */
const STORES = {
  USER_DATA: 'fp_users_v6',
  FEED_DATA: 'fp_content_v6',
  TRENDING_CACHE: 'fp_trending_v6', // Will be suffixed with _[lang]
  SYSTEM_TICKER: 'fp_ticker_v6',     // Will be suffixed with _[lang]
  ACTIVITY_LOG: 'fp_activity_v6',
  TRAINING_SET: 'fp_training_v6',
  META: 'fp_meta_v6'
};

const CACHE_TTL = 1000 * 60 * 30; // 30 minutes
const MAX_LOG_SIZE = 50;

const storage = {
  get: <T>(key: string, fallback: T): T => {
    try {
      const data = localStorage.getItem(key);
      return data ? JSON.parse(data) : fallback;
    } catch (e) {
      return fallback;
    }
  },
  set: <T>(key: string, value: T): void => {
    try {
      localStorage.setItem(key, JSON.stringify(value));
    } catch (e) {
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        localStorage.clear(); // Emergency flush
      }
    }
  }
};

export const db = {
  users: {
    all: () => storage.get<User[]>(STORES.USER_DATA, []),
    save: (user: User) => {
      const users = db.users.all();
      const idx = users.findIndex(u => u.id === user.id);
      if (idx > -1) users[idx] = user;
      else users.push(user);
      storage.set(STORES.USER_DATA, users);
    },
    findByEmail: (email: string) => db.users.all().find(u => u.email.toLowerCase() === email.trim().toLowerCase()),
    delete: (id: string) => storage.set(STORES.USER_DATA, db.users.all().filter(u => u.id !== id)),
    getLeaderboard: () => [...db.users.all()].sort((a, b) => b.stats.points - a.stats.points).slice(0, 100)
  },
  content: {
    getFeed: () => storage.get<FactCheckResult[]>(STORES.FEED_DATA, []),
    saveCheck: (check: FactCheckResult) => {
      const feed = db.content.getFeed();
      const optimizedCheck = { ...check, imageUrl: check.imageUrl?.startsWith('data:image') ? undefined : check.imageUrl };
      storage.set(STORES.FEED_DATA, [optimizedCheck, ...feed].slice(0, 25));
    },
    delete: (id: string) => {
      const feed = storage.get<FactCheckResult[]>(STORES.FEED_DATA, []);
      storage.set(STORES.FEED_DATA, feed.filter(i => i.id !== id));
    },
    // Multi-language trending cache
    getTrending: (lang: string = 'en') => storage.get<FactCheckResult[]>(`${STORES.TRENDING_CACHE}_${lang}`, []),
    saveTrending: (data: FactCheckResult[], lang: string = 'en') => {
      storage.set(`${STORES.TRENDING_CACHE}_${lang}`, data);
      const metaKey = `${STORES.META}_${lang}`;
      storage.set(metaKey, { lastFetch: Date.now() });
    },
    updateVote: (id: string, option: keyof FactCheckResult['communityPoll']) => {
        // Update main feed
        const feed = storage.get<FactCheckResult[]>(STORES.FEED_DATA, []);
        const item = feed.find(i => i.id === id);
        if (item) {
          (item.communityPoll[option] as number)++;
          item.communityPoll.total++;
          storage.set(STORES.FEED_DATA, feed);
          if (item.communityPoll.total > 5) db.training.addExample(item);
        }
    },
    isCacheStale: (lang: string = 'en') => {
      const meta = storage.get<{lastFetch?: number}>(`${STORES.META}_${lang}`, {});
      return !meta.lastFetch || (Date.now() - meta.lastFetch > CACHE_TTL);
    }
  },
  training: {
    getSet: () => storage.get<any[]>(STORES.TRAINING_SET, []),
    addExample: (result: FactCheckResult) => {
      const set = db.training.getSet();
      if (set.find(s => s.id === result.id)) return;
      const example = {
        id: result.id,
        instruction: `Verify: "${result.claim}"`,
        response: { verdict: result.verdict, confidence: result.confidenceScore }
      };
      storage.set(STORES.TRAINING_SET, [...set, example].slice(-100));
    }
  },
  analytics: {
    getTicker: (lang: string = 'en') => storage.get<TickerItem[]>(`${STORES.SYSTEM_TICKER}_${lang}`, []),
    saveTicker: (items: TickerItem[], lang: string = 'en') => storage.set(`${STORES.SYSTEM_TICKER}_${lang}`, items),
    getLogs: () => storage.get<Activity[]>(STORES.ACTIVITY_LOG, []),
    log: (userId: string, userName: string, action: string) => {
      const logs = db.analytics.getLogs();
      const entry: Activity = {
        id: `log-${Date.now()}`,
        userId, userName, action, timestamp: Date.now()
      };
      storage.set(STORES.ACTIVITY_LOG, [entry, ...logs].slice(0, MAX_LOG_SIZE));
    }
  }
};

import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { FactCheckResult, VerdictType, Source, TickerItem } from "../types";
import { db } from "./db";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const normalizeVerdict = (verdict: string): VerdictType => {
  const v = (verdict || "").toUpperCase().trim();
  if (v.includes("TRUE") || v.includes("AUTHENTIC") || v.includes("FACT")) return VerdictType.TRUE;
  if (v.includes("FALSE") || v.includes("FAKE") || v.includes("FABRICATED")) return VerdictType.FALSE;
  if (v.includes("MISLEADING") || v.includes("CONTEXT") || v.includes("PARTIAL")) return VerdictType.MISLEADING;
  return VerdictType.UNVERIFIED;
};

const cleanJsonString = (text: string): string => {
  if (!text) return "";
  const firstBrace = text.indexOf('{');
  const firstBracket = text.indexOf('[');
  let start = -1, end = -1, stack = 0, charOpen = '', charClose = '';
  if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
    start = firstBrace; charOpen = '{'; charClose = '}';
  } else if (firstBracket !== -1) {
    start = firstBracket; charOpen = '['; charClose = ']';
  }
  if (start === -1) return text.trim();
  for (let i = start; i < text.length; i++) {
    if (text[i] === charOpen) stack++;
    if (text[i] === charClose) {
      stack--;
      if (stack === 0) { end = i; break; }
    }
  }
  return (start !== -1 && end !== -1) ? text.substring(start, end + 1) : text.trim();
};

const getNewsImage = (keyword: string): string => {
  const seed = encodeURIComponent(keyword.substring(0, 15));
  return `https://picsum.photos/seed/${seed}/800/450`;
};

export const fetchRealTopNews = async (langCode: string, langName: string): Promise<TickerItem[]> => {
    // Check cache first for instant load
    const cached = db.analytics.getTicker(langCode);
    if (cached.length > 0 && !db.content.isCacheStale(langCode)) return cached;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: [{ 
              parts: [{ 
                text: `Search for 8 current global news headlines. Translate "headline" and "source" to ${langName}. Return JSON: [{"headline":"...", "verdict":"TRUE"|"FALSE", "source":"..."}]` 
              }] 
            }],
            config: { 
              tools: [{ googleSearch: {} }], 
              temperature: 0.1,
              systemInstruction: `You are a multi-lingual news wire. Output only valid JSON in ${langName}.`
            }
        });

        const data = JSON.parse(cleanJsonString(response.text || "[]"));
        if (Array.isArray(data) && data.length > 0) {
            const normalized = data.map((item: any) => ({
                ...item,
                verdict: normalizeVerdict(item.verdict) === VerdictType.TRUE ? 'TRUE' : 'FALSE'
            }));
            db.analytics.saveTicker(normalized, langCode);
            return normalized;
        }
    } catch (e) { console.error("Ticker error:", e); }
    return cached;
};

export const analyzeClaim = async (text: string, langName: string, imageBase64?: string): Promise<any> => {
  const startTime = Date.now();
  const parts: any[] = [];
  if (imageBase64) parts.push({ inlineData: { data: imageBase64, mimeType: "image/jpeg" } });

  const prompt = `Verify: "${text}". Target: ${langName}. Return JSON: {verdict, headline, summary, keyPoints, confidenceScore, bias, searchQueries}`;
  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts }],
      config: {
        systemInstruction: `Fact-Checking Expert. Return all text in ${langName}.`,
        tools: [{ googleSearch: {} }],
        temperature: 0,
        thinkingConfig: { thinkingBudget: 8000 } // Reduced budget for speed
      }
    });

    const json = JSON.parse(cleanJsonString(response.text || "{}"));
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources: Source[] = Array.from(new Map<string, Source>(
      chunks.filter((c: any) => c.web?.uri).map((c: any) => [c.web.uri, { title: c.web.title || "Source", uri: c.web.uri }])
    ).values());

    return {
      claim: text,
      verdict: normalizeVerdict(json.verdict),
      explanation: json.summary || "Pending...",
      headline: json.headline || "Detection Result",
      keyPoints: json.keyPoints || [],
      confidenceScore: json.confidenceScore || 50,
      biasRating: json.bias || 'NEUTRAL',
      sources: sources,
      imageUrl: imageBase64 ? `data:image/jpeg;base64,${imageBase64}` : undefined,
      communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
      analysisTime: Date.now() - startTime
    };
  } catch (error) { throw error; }
};

export const fetchTrendingDebunks = async (langCode: string, langName: string, forceRefresh = false): Promise<FactCheckResult[]> => {
    const cached = db.content.getTrending(langCode);
    if (!forceRefresh && cached.length > 0 && !db.content.isCacheStale(langCode)) return cached;

    try {
       const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [{ parts: [{ text: `List 4 viral social media claims today. Provide headline and summary in ${langName}. Return JSON: [{headline, summary, verdict, sourceName, bias}]` }] }],
        config: { tools: [{ googleSearch: {} }], temperature: 0.5 }
      });
      const data = JSON.parse(cleanJsonString(response.text || "[]"));
      const results = data.map((item: any, i: number) => ({
          id: `trend-${langCode}-${Date.now()}-${i}`,
          claim: item.headline,
          verdict: normalizeVerdict(item.verdict),
          explanation: item.summary,
          headline: item.headline,
          keyPoints: ["AI search grounded verification"],
          sources: [{ title: item.sourceName || "Source", uri: "#" }],
          timestamp: Date.now(),
          confidenceScore: 85,
          biasRating: item.bias || 'NEUTRAL',
          communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
          author: "Truth Engine",
          imageUrl: getNewsImage(item.headline)
      }));
      db.content.saveTrending(results, langCode);
      return results;
    } catch (e) { return cached; }
};

