  const loadContent = async (force = false) => {
    // If we have cached content for this language, show it instantly
    const cached = db.content.getTrending(language);
    if (cached.length > 0 && !force) {
        setTrendingChecks(cached);
        // Silently update in background if stale
        if (db.content.isCacheStale(language)) {
            fetchTrendingDebunks(language, langName, true).then(fresh => setTrendingChecks(fresh));
        }
        return;
    }

    setLoading(true);
    try {
