import React, { useState, useRef, useEffect } from 'react';
import { Loader2, Search, Image as ImageIcon, ExternalLink, ShieldCheck, Cpu, Globe, Link as LinkIcon, AlertCircle, FileCheck, X, Zap, ArrowRight, Shield } from 'lucide-react';
import { analyzeClaim } from '../services/geminiService';
import { FactCheckResult } from '../types';
import { VerdictBadge } from '../components/VerdictBadge';
import { useAuth } from '../context/AuthContext';
import { useLanguage, LANGUAGES } from '../context/LanguageContext';

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
const ALLOWED_TYPES = ['image/jpeg', 'image/png'];

export const Verify: React.FC = () => {
  const [claim, setClaim] = useState('');
  const [image, setImage] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [status, setStatus] = useState('');
  const [result, setResult] = useState<any>(null);
  const [fileError, setFileError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const statusIntervalRef = useRef<number | null>(null);
  const { user, submitCheck } = useAuth();
  const { t, language } = useLanguage();

  const langName = LANGUAGES.find(l => l.code === language)?.name || 'English';

  useEffect(() => {
    return () => { 
      if (previewUrl?.startsWith('blob:')) URL.revokeObjectURL(previewUrl); 
      if (statusIntervalRef.current) clearInterval(statusIntervalRef.current);
    };
  }, [previewUrl]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFileError(null);
    const file = e.target.files?.[0];
    if (!file) return;
    if (!ALLOWED_TYPES.includes(file.type)) {
      setFileError('Unsupported file type. Please upload JPG or PNG.');
      return;
    }
    if (file.size > MAX_FILE_SIZE) {
      setFileError('File size exceeds 5MB limit.');
      return;
    }
    setImage(file);
    setPreviewUrl(URL.createObjectURL(file));
  };

  const clearImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setImage(null);
    if (previewUrl) URL.revokeObjectURL(previewUrl);
    setPreviewUrl(null);
    setFileError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (fileError || (!claim && !image)) return;

    setIsAnalyzing(true);
    setResult(null);

    const statuses = [
      'Initializing Neural Link...',
      'Accessing Google Search Index...',
      'Cross-referencing social media signals...',
      'Validating external source reliability...',
      'Synthesizing forensic report...'
    ];

    let statusIdx = 0;
    setStatus(statuses[0]);
    statusIntervalRef.current = window.setInterval(() => {
      statusIdx = (statusIdx + 1) % statuses.length;
      setStatus(statuses[statusIdx]);
    }, 2500);

    let base64Image = undefined;
    if (image) {
      const reader = new FileReader();
      base64Image = await new Promise<string>((resolve) => {
        reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(image);
      });
    }

    try {
      const analysis = await analyzeClaim(claim, langName, base64Image);
      const newCheck: FactCheckResult = {
        ...analysis,
        id: Date.now().toString(),
        timestamp: Date.now(),
        author: user ? user.name : 'System Node'
      };
      submitCheck(newCheck);
      setResult(analysis);
    } catch (err) {
      console.error(err);
      setFileError("Detection failed. Neural nodes are currently saturated.");
    } finally {
      setIsAnalyzing(false);
      setStatus('');
      if (statusIntervalRef.current) clearInterval(statusIntervalRef.current);
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-4 py-8">
      <div className="text-center mb-10">
        <h1 className="text-4xl md:text-6xl font-black text-white mb-4 tracking-tighter uppercase italic">
            Truth <span className="text-primary-500">Scanner</span>
        </h1>
        <p className="text-slate-400 text-lg max-w-2xl mx-auto font-medium">
          Instant social media verification powered by Google Search Grounding.
        </p>
      </div>

      <div className="grid grid-cols-1 gap-8">
          <div className="bg-slate-900/50 backdrop-blur-xl rounded-[2.5rem] border border-white/5 shadow-2xl overflow-hidden p-1">
             <div className="bg-slate-900 rounded-[2.2rem] p-8 md:p-12">
                <form onSubmit={handleSubmit} className="space-y-8">
                    <div className="relative">
                        <textarea
                            value={claim}
                            onChange={(e) => setClaim(e.target.value)}
                            placeholder="Paste the news headline or social media post text here..."
                            className="w-full h-40 px-6 py-6 bg-black/50 border border-white/5 text-white rounded-3xl focus:ring-2 focus:ring-primary-600 outline-none transition-all resize-none text-lg font-medium placeholder-slate-700 shadow-inner"
                        />
                        <div className="absolute bottom-4 right-4 flex items-center gap-2 px-3 py-1.5 bg-white/5 rounded-full border border-white/5">
                            <Zap className="w-3 h-3 text-amber-500" />
                            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Grounding Active</span>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div 
                            onClick={() => fileInputRef.current?.click()}
                            className={`group relative border-2 border-dashed rounded-[2rem] p-8 text-center cursor-pointer transition-all duration-300 ${previewUrl ? 'border-primary-500 bg-primary-500/5' : 'border-white/5 hover:border-white/20 hover:bg-white/5'}`}
                        >
                            {previewUrl ? (
                                <div className="relative group/img">
                                    <img src={previewUrl} alt="Preview" className="max-h-40 mx-auto rounded-2xl shadow-2xl" />
                                    <button onClick={clearImage} className="absolute -top-4 -right-4 bg-red-600 p-2 rounded-full shadow-lg hover:scale-110 transition-transform"><X className="w-4 h-4 text-white" /></button>
                                </div>
                            ) : (
                                <div className="space-y-4">
                                    <div className="w-16 h-16 bg-white/5 rounded-3xl flex items-center justify-center mx-auto group-hover:scale-110 transition-transform">
                                        <ImageIcon className="w-8 h-8 text-slate-500" />
                                    </div>
                                    <div>
                                        <p className="text-xs font-black text-white uppercase tracking-widest">Visual Evidence</p>
                                        <p className="text-[10px] text-slate-500 mt-1">Upload Screenshot (Max 5MB)</p>
                                    </div>
                                </div>
                            )}
                            <input type="file" ref={fileInputRef} className="hidden" accept="image/jpeg,image/png" onChange={handleImageChange} />
                            {fileError && <p className="mt-4 text-xs text-red-500 font-bold px-4 py-2 bg-red-500/10 rounded-xl border border-red-500/20">{fileError}</p>}
                        </div>

                        <button
                            type="submit"
                            disabled={isAnalyzing || !!fileError || (!claim && !image)}
                            className="group relative h-full py-8 rounded-[2rem] font-black text-2xl bg-primary-600 text-white hover:bg-primary-500 disabled:opacity-50 transition-all flex flex-col items-center justify-center gap-4 shadow-xl shadow-primary-900/40 overflow-hidden"
                        >
                            {isAnalyzing ? (
                                <>
                                    <div className="relative">
                                        <Loader2 className="animate-spin w-12 h-12 text-white/50" />
                                        <div className="absolute inset-0 flex items-center justify-center">
                                            <Search className="w-5 h-5 text-white" />
                                        </div>
                                    </div>
                                    <span className="text-xs font-mono uppercase tracking-[0.2em] animate-pulse">{status}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center group-hover:scale-110 transition-transform">
                                        <ShieldCheck className="w-10 h-10" />
                                    </div>
                                    <span className="tracking-tighter italic uppercase">{t('btn_scan')}</span>
                                </>
                            )}
                            {/* Animated background lines */}
                            <div className="absolute inset-0 opacity-10 pointer-events-none">
                                <div className="absolute top-0 left-0 w-full h-full bg-[linear-gradient(45deg,transparent_25%,rgba(255,255,255,0.2)_50%,transparent_75%)] bg-[length:250%_250%] animate-[shimmer_3s_infinite]"></div>
                            </div>
                        </button>
                    </div>
                </form>
             </div>
          </div>

          {result && (
            <div className="animate-scale-in space-y-8">
               <div className="bg-slate-900/80 backdrop-blur-xl rounded-[3rem] border border-white/10 shadow-2xl overflow-hidden">
                   <div className="p-8 md:p-12">
                       <div className="flex flex-col md:flex-row md:items-start justify-between gap-8 mb-12">
                           <div className="space-y-6 flex-1">
                               <div className="flex items-center gap-4">
                                    <VerdictBadge verdict={result.verdict} className="text-lg py-2 px-6" />
