import React, { useState, useRef, useEffect } from 'react';
import { Loader2, Search, Image as ImageIcon, ExternalLink, ShieldCheck, Cpu, Globe, Link as LinkIcon, AlertCircle, FileCheck, X, Zap, ArrowRight, Shield, FileText, TrendingUp } from 'lucide-react';
import { analyzeClaim } from '../services/geminiService';
import { FactCheckResult } from '../types';
import { VerdictBadge } from '../components/VerdictBadge';
import { useAuth } from '../context/AuthContext';
import { useLanguage, LANGUAGES } from '../context/LanguageContext';

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
const ALLOWED_IMAGE_TYPES = ['image/jpeg', 'image/png'];
const ALLOWED_FILE_TYPES = ['text/plain', 'application/json'];

export const Verify: React.FC = () => {
  const [claim, setClaim] = useState('');
  const [image, setImage] = useState<File | null>(null);
  const [insaveFile, setInsaveFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [status, setStatus] = useState('');
  const [result, setResult] = useState<FactCheckResult | null>(null);
  const [batchResults, setBatchResults] = useState<FactCheckResult[]>([]);
  const [fileError, setFileError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const insaveInputRef = useRef<HTMLInputElement>(null);
  const statusIntervalRef = useRef<number | null>(null);

  const { user, submitCheck } = useAuth();
  const { t, language } = useLanguage();

  const langName = LANGUAGES.find(l => l.code === language)?.name || 'English';

  useEffect(() => {
    return () => { 
      if (previewUrl?.startsWith('blob:')) URL.revokeObjectURL(previewUrl); 
      if (statusIntervalRef.current) clearInterval(statusIntervalRef.current);
    };
  }, [previewUrl]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFileError(null);
    const file = e.target.files?.[0];
    if (!file) return;
    if (!ALLOWED_IMAGE_TYPES.includes(file.type)) {
      setFileError('Unsupported image type. Use JPG/PNG.');
      return;
    }
    setImage(file);
    setPreviewUrl(URL.createObjectURL(file));
  };

  const handleInsaveChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) setInsaveFile(file);
  };

  const processInsaveFile = async () => {
    if (!insaveFile) return;
    setIsAnalyzing(true);
    setBatchResults([]);

    try {
      const text = await insaveFile.text();
      let claims: string[] = [];

      if (insaveFile.type === 'application/json' || insaveFile.name.endsWith('.json')) {
        const json = JSON.parse(text);
        claims = Array.isArray(json) ? json.map(i => i.text || i.claim || i) : [json.text || json.claim];
      } else {
        claims = text.split('\n').filter(line => line.trim().length > 10);
      }

      for (const c of claims.slice(0, 5)) { // Limit batch for demo safety
        setStatus(`Analyzing batch item: ${c.substring(0, 20)}...`);
        const analysis = await analyzeClaim(c, langName);
        submitCheck(analysis);
        setBatchResults(prev => [analysis, ...prev]);
      }
    } catch (e) {
      setFileError("Failed to parse insave file.");
    } finally {
      setIsAnalyzing(false);
      setInsaveFile(null);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (insaveFile) {
        processInsaveFile();
        return;
    }
    if (fileError || (!claim && !image)) return;

    setIsAnalyzing(true);
    setResult(null);

    const statuses = [
      'Initializing Neural Link...',
      'Accessing Google Search Index...',
      'Mapping GARM Safety Standards...',
      'Estimating HFT Volatility Risk...',
      'Validating Source Integrity...'
    ];

    let statusIdx = 0;
    setStatus(statuses[0]);
    statusIntervalRef.current = window.setInterval(() => {
      statusIdx = (statusIdx + 1) % statuses.length;
      setStatus(statuses[statusIdx]);
    }, 2000);

    let base64Image = undefined;
    if (image) {
      const reader = new FileReader();
      base64Image = await new Promise<string>((resolve) => {
        reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(image);
      });
    }

    try {
      const analysis = await analyzeClaim(claim, langName, base64Image);
      submitCheck(analysis);
      setResult(analysis);
    } catch (err) {
      setFileError("Detection nodes saturated. Retrying link...");
    } finally {
      setIsAnalyzing(false);
      setStatus('');
      if (statusIntervalRef.current) clearInterval(statusIntervalRef.current);
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-4 py-8">
