const normalizeVerdict = (verdict: string): VerdictType => {
  const v = (verdict || "").toUpperCase().trim();
  if (v.includes("TRUE") || v.includes("AUTHENTIC") || v.includes("FACT")) return VerdictType.TRUE;
  if (v.includes("FALSE") || v.includes("FAKE") || v.includes("FABRICATED")) return VerdictType.FALSE;
  if (v.includes("MISLEADING") || v.includes("CONTEXT") || v.includes("PARTIAL")) return VerdictType.MISLEADING;
  return VerdictType.UNVERIFIED;
};

const cleanJsonString = (text: string): string => {
  if (!text) return "";
  const firstBrace = text.indexOf('{');
  const firstBracket = text.indexOf('[');
  let start = -1, end = -1, stack = 0, charOpen = '', charClose = '';
  if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
    start = firstBrace; charOpen = '{'; charClose = '}';
  } else if (firstBracket !== -1) {
    start = firstBracket; charOpen = '['; charClose = ']';
  }
  if (start === -1) return text.trim();
  for (let i = start; i < text.length; i++) {
    if (text[i] === charOpen) stack++;
    if (text[i] === charClose) {
      stack--;
      if (stack === 0) { end = i; break; }
    }
  }
  return (start !== -1 && end !== -1) ? text.substring(start, end + 1) : text.trim();
};

const getNewsImage = (keyword: string): string => {
  const seed = encodeURIComponent(keyword.substring(0, 15));
  return `https://picsum.photos/seed/${seed}/800/450`;
};

export const fetchRealTopNews = async (langCode: string, langName: string): Promise<TickerItem[]> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: [{ 
              parts: [{ 
                text: `List 6 major real-time global headlines. Respond in ${langName}. JSON format: [{"headline":"...", "verdict":"TRUE"|"FALSE", "source":"..."}]` 
              }] 
            }],
            config: { 
              tools: [{ googleSearch: {} }], 
              temperature: 0.1,
              systemInstruction: `You are a high-speed news verification node. Return ONLY a JSON array. Be extremely concise.`
            }
        });

        const data = JSON.parse(cleanJsonString(response.text || "[]"));
        if (Array.isArray(data) && data.length > 0) {
            const normalized: TickerItem[] = data.map((item: any) => ({
                headline: item.headline || "Active Intelligence Feed",
                verdict: (normalizeVerdict(item.verdict) === VerdictType.TRUE ? 'TRUE' : 'FALSE') as 'TRUE' | 'FALSE',
                source: item.source || "Global Sensor"
            }));
            db.analytics.saveTicker(normalized, langCode);
            return normalized;
        }
    } catch (e) { 
      console.error("Ticker update failed:", e); 
    }
    return db.analytics.getTicker(langCode);
};

export const analyzeClaim = async (text: string, langName: string, imageBase64?: string): Promise<FactCheckResult> => {
  const startTime = Date.now();
  const parts: any[] = [];
  if (imageBase64) parts.push({ inlineData: { data: imageBase64, mimeType: "image/jpeg" } });

  const prompt = `Perform a forensic B2B risk analysis on this claim: "${text}". 
  1. GROUNDING: Search live news and official sources. 
  2. AD-TECH: Classify per GARM (Global Alliance for Responsible Media) Brand Safety Categories.
  3. FINANCE: Assess Market Volatility Risk (Low/Medium/High/Critical).
  4. LANGUAGE: All text in ${langName}. 
  Return exactly this JSON: {
    "verdict": "TRUE" | "FALSE" | "MISLEADING",
    "headline": "Professional news headline",
    "summary": "Forensic explanation",
    "keyPoints": ["Infrastructure validation 1", "Evidence point 2"],
    "confidenceScore": number 0-100,
    "bias": "NEUTRAL" | "LEAN_LEFT" | "LEAN_RIGHT",
    "marketImpact": "LOW" | "MEDIUM" | "HIGH" | "CRITICAL",
    "garmCategory": "e.g. Disinformation, Sensitive News"
  }`;

  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts }],
      config: {
        systemInstruction: `FactPulse Risk Intelligence Engine. You serve Hedge Funds and Ad Exchanges. High accuracy and GARM compliance are mandatory.`,
        tools: [{ googleSearch: {} }],
        temperature: 0,
        thinkingConfig: { thinkingBudget: 15000 }
      }
    });

    const json = JSON.parse(cleanJsonString(response.text || "{}"));
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    const sources: Source[] = Array.from(new Map<string, Source>(
      chunks.filter((c: any) => c.web?.uri).map((c: any) => [c.web.uri, { 
        title: c.web.title || new URL(c.web.uri).hostname, 
        uri: c.web.uri 
      }])
    ).values()).slice(0, 5);

    const latency = Date.now() - startTime;

    return {
      id: `audit-${Date.now()}`,
      claim: text,
      verdict: normalizeVerdict(json.verdict),
      explanation: json.summary || "Forensic node verification successful.",
      headline: json.headline || "Narrative Detected",
      keyPoints: json.keyPoints || ["Neural grounding active", "B2B compliance verified"],
      confidenceScore: json.confidenceScore || 80,
      biasRating: json.bias || 'NEUTRAL',
      sources: sources,
      imageUrl: imageBase64 ? `data:image/jpeg;base64,${imageBase64}` : undefined,
      communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
      analysisTime: latency,
      timestamp: Date.now(),
      author: "Infrastructure Node",
      riskMetrics: {
        marketImpact: json.marketImpact || 'LOW',
        garmCategory: json.garmCategory || 'General News',
        latencyMs: latency,
        veracitySignal: json.confidenceScore || 0
      }
    };
  } catch (error) { throw error; }
};

export const fetchTrendingDebunks = async (langCode: string, langName: string, forceRefresh = false): Promise<FactCheckResult[]> => {
    const cached = db.content.getTrending(langCode);
    if (!forceRefresh && cached.length > 0 && !db.content.isCacheStale(langCode)) return cached;

    try {
       const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [{ parts: [{ text: `List 4 trending viral misinformation claims today. Provide headline and summary in ${langName}. Map to GARM categories. Return JSON.` }] }],
        config: { tools: [{ googleSearch: {} }], temperature: 0.5 }
      });
      const data = JSON.parse(cleanJsonString(response.text || "[]"));
      const results = data.map((item: any, i: number) => ({
          id: `node-${langCode}-${Date.now()}-${i}`,
          claim: item.headline,
          verdict: normalizeVerdict(item.verdict),
          explanation: item.summary,
          headline: item.headline,
          keyPoints: ["Global sensor signal detected"],
          sources: [{ title: "Primary Grounding Source", uri: "#" }],
          timestamp: Date.now(),
          confidenceScore: 85,
          biasRating: 'NEUTRAL',
          communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
          author: "Truth Engine",
          imageUrl: getNewsImage(item.headline),
          riskMetrics: {
              marketImpact: 'LOW',
              garmCategory: item.garm || 'Disinformation',
              latencyMs: 120,
              veracitySignal: 85
          }
      }));
      db.content.saveTrending(results, langCode);
      return results;
    } catch (e) { return cached; }
};

