export const analyzeClaim = async (text: string, langName: string, imageBase64?: string): Promise<FactCheckResult> => {
  const startTime = Date.now();
  const parts: any[] = [];
  if (imageBase64) parts.push({ inlineData: { data: imageBase64, mimeType: "image/jpeg" } });

  const prompt = `Perform a high-precision forensic audit on this claim: "${text}".

  REQUIRED METRICS:
  1. GROUNDING: Search live news and official sources.
  2. TRUST SCORING: Evaluate top publishers for domain age, historical accuracy, and reliability.
  3. VIRALITY: Estimate spread velocity (0-100) and cross-platform reposting risk.
  4. REASONING: Break down the verification process into 4 clear steps.

  RESPOND IN ${langName} JSON:
  {
    "verdict": "TRUE" | "FALSE" | "MISLEADING",
    "headline": "Short professional headline",
    "summary": "Forensic breakdown of the evidence",
    "confidenceScore": 0-100,
    "bias": "NEUTRAL" | "LEAN_LEFT" | "LEAN_RIGHT",
    "marketImpact": "LOW" | "MEDIUM" | "HIGH" | "CRITICAL",
    "garmCategory": "Disinformation/News",
    "viralityRisk": 0-100,
    "reasoningSteps": [
      {"title": "Step Name", "description": "What was analyzed"}
    ],
    "sourceMetadata": [
      {"uri": "...", "trustScore": 0-100, "reliability": "VERIFIED" | "SUSPICIOUS" | "UNRANKED"}
    ]
  }`;

  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts }],
      config: {
        systemInstruction: `FactPulse Deep Auditor. You serve B2B Risk Intelligence. High accuracy is mandatory.`,
        tools: [{ googleSearch: {} }],
        temperature: 0,
        thinkingConfig: { thinkingBudget: 15000 }
      }
    });

    const json = JSON.parse(cleanJsonString(response.text || "{}"));
    const v = normalizeVerdict(json.verdict);
    const score = json.confidenceScore || 75;

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources: Source[] = chunks.filter((c: any) => c.web?.uri).map((c: any) => {
      const meta = (json.sourceMetadata || []).find((m: any) => m.uri === c.web.uri);
      return {
        title: c.web.title || new URL(c.web.uri).hostname,
        uri: c.web.uri,
        trustScore: meta?.trustScore || 70,
        reliabilityBadge: meta?.reliability || 'VERIFIED'
      };
    }).slice(0, 5);

    const latency = Date.now() - startTime;

    return {
      id: `audit-${Date.now()}`,
      claim: text,
      verdict: v,
      confidenceLevel: normalizeConfidenceLevel(score, v),
      explanation: json.summary || "Forensic node verification successful.",
      headline: json.headline || "Narrative Detected",
      reasoningTimeline: (json.reasoningSteps || []).map((s: any) => ({ ...s, status: 'COMPLETE' })),
      sources: sources,
      timestamp: Date.now(),
      confidenceScore: score,
      communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
      author: "Infrastructure Node",
      analysisTime: latency,
      riskMetrics: {
        marketImpact: json.marketImpact || 'LOW',
        garmCategory: json.garmCategory || 'General News',
        latencyMs: latency,
        veracitySignal: score,
        viralityRisk: json.viralityRisk || 50
      }
    };
  } catch (error) { throw error; }
};

