const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const normalizeConfidenceLevel = (score: number, verdict: VerdictType): ConfidenceLevel => {
  if (verdict === VerdictType.TRUE) {
    return score > 85 ? ConfidenceLevel.AUTHENTIC : ConfidenceLevel.LIKELY_AUTHENTIC;
  }
  if (verdict === VerdictType.FALSE) {
    return score > 85 ? ConfidenceLevel.FABRICATED : ConfidenceLevel.LIKELY_FABRICATED;
  }
  return ConfidenceLevel.UNVERIFIED;
};

const normalizeVerdict = (verdict: string): VerdictType => {
  const v = (verdict || "").toUpperCase().trim();
  if (v.includes("TRUE") || v.includes("AUTHENTIC") || v.includes("FACT")) return VerdictType.TRUE;
  if (v.includes("FALSE") || v.includes("FAKE") || v.includes("FABRICATED")) return VerdictType.FALSE;
  if (v.includes("MISLEADING") || v.includes("CONTEXT") || v.includes("PARTIAL")) return VerdictType.MISLEADING;
  return VerdictType.UNVERIFIED;
};

const cleanJsonString = (text: string): string => {
  if (!text) return "";
  const firstBrace = text.indexOf('{');
  const firstBracket = text.indexOf('[');
  let start = -1, end = -1, stack = 0, charOpen = '', charClose = '';
  if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
    start = firstBrace; charOpen = '{'; charClose = '}';
  } else if (firstBracket !== -1) {
    start = firstBracket; charOpen = '['; charClose = ']';
  }
  if (start === -1) return text.trim();
  for (let i = start; i < text.length; i++) {
    if (text[i] === charOpen) stack++;
    if (text[i] === charClose) {
      stack--;
      if (stack === 0) { end = i; break; }
    }
  }
  return (start !== -1 && end !== -1) ? text.substring(start, end + 1) : text.trim();
};

export const fetchRealTopNews = async (langCode: string, langName: string): Promise<TickerItem[]> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: [{ 
              parts: [{ 
                text: `List 6 major real-time global headlines. Respond in ${langName}. JSON format: [{"headline":"...", "verdict":"TRUE"|"FALSE", "source":"..."}]` 
              }] 
            }],
            config: { 
              tools: [{ googleSearch: {} }], 
              temperature: 0.1,
              systemInstruction: `You are a high-speed news verification node. Return ONLY a JSON array. Be extremely concise.`
            }
        });

        const data = JSON.parse(cleanJsonString(response.text || "[]"));
        if (Array.isArray(data) && data.length > 0) {
            return data.map((item: any) => ({
                headline: item.headline || "Active Intelligence Feed",
                verdict: (normalizeVerdict(item.verdict) === VerdictType.TRUE ? 'TRUE' : 'FALSE') as 'TRUE' | 'FALSE',
                source: item.source || "Global Sensor"
            }));
        }
    } catch (e) { 
      console.error("Ticker update failed:", e); 
    }
    return [];
};

export const analyzeClaim = async (text: string, langName: string, imageBase64?: string): Promise<FactCheckResult> => {
  const startTime = Date.now();
  const parts: any[] = [];
  if (imageBase64) parts.push({ inlineData: { data: imageBase64, mimeType: "image/jpeg" } });

  const prompt = `Perform a high-precision forensic audit on this claim: "${text}".

  REQUIRED METRICS:
  1. GROUNDING: Search live news and official sources.
  2. TRUST SCORING: Evaluate top publishers for domain age, historical accuracy, and reliability.
  3. VIRALITY: Estimate spread velocity (0-100) and cross-platform reposting risk.
  4. REASONING: Break down the verification process into 4 clear steps.

  RESPOND IN ${langName} JSON:
  {
    "verdict": "TRUE" | "FALSE" | "MISLEADING",
    "headline": "Short professional headline",
    "summary": "Forensic breakdown of the evidence",
    "confidenceScore": 0-100,
    "bias": "NEUTRAL" | "LEAN_LEFT" | "LEAN_RIGHT",
    "marketImpact": "LOW" | "MEDIUM" | "HIGH" | "CRITICAL",
    "garmCategory": "Disinformation/News",
    "viralityRisk": 0-100,
    "reasoningSteps": [
      {"title": "Step Name", "description": "What was analyzed"}
    ],
    "sourceMetadata": [
      {"uri": "...", "trustScore": 0-100, "reliability": "VERIFIED" | "SUSPICIOUS" | "UNRANKED"}
    ]
  }`;

  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts }],
      config: {
        systemInstruction: `FactPulse Deep Auditor. You serve B2B Risk Intelligence. High accuracy is mandatory.`,
        tools: [{ googleSearch: {} }],
        temperature: 0,
        thinkingConfig: { thinkingBudget: 15000 }
      }
    });

    const json = JSON.parse(cleanJsonString(response.text || "{}"));
    const v = normalizeVerdict(json.verdict);
    const score = json.confidenceScore || 75;

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources: Source[] = chunks.filter((c: any) => c.web?.uri).map((c: any) => {
      const meta = (json.sourceMetadata || []).find((m: any) => m.uri === c.web.uri);
      return {
        title: c.web.title || new URL(c.web.uri).hostname,
        uri: c.web.uri,
        trustScore: meta?.trustScore || 70,
        reliabilityBadge: meta?.reliability || 'VERIFIED'
      };
    }).slice(0, 5);

    const latency = Date.now() - startTime;

    return {
      id: `audit-${Date.now()}`,
      claim: text,
      verdict: v,
      confidenceLevel: normalizeConfidenceLevel(score, v),
      explanation: json.summary || "Forensic node verification successful.",
      headline: json.headline || "Narrative Detected",
      reasoningTimeline: (json.reasoningSteps || []).map((s: any) => ({ ...s, status: 'COMPLETE' })),
      sources: sources,
      timestamp: Date.now(),
      confidenceScore: score,
      communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
      author: "Infrastructure Node",
      analysisTime: latency,
      riskMetrics: {
        marketImpact: json.marketImpact || 'LOW',
        garmCategory: json.garmCategory || 'General News',
        latencyMs: latency,
        veracitySignal: score,
        viralityRisk: json.viralityRisk || 50
      }
    };
  } catch (error) { throw error; }
};

// Fixed: fetchTrendingDebunks updated to accept an optional 'force' parameter to match callers in Home.tsx and AuthContext.tsx.
// It also extracts grounding sources from response metadata and persists the results to the local database cache.
export const fetchTrendingDebunks = async (langCode: string, langName: string, force: boolean = false): Promise<FactCheckResult[]> => {
    try {
       const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [{ parts: [{ text: `List 4 viral social media claims today in ${langName}. Return JSON: [{headline, summary, verdict}]` }] }],
        config: { tools: [{ googleSearch: {} }], temperature: 0.5 }
      });
      const data = JSON.parse(cleanJsonString(response.text || "[]"));

      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources: Source[] = chunks.filter((c: any) => c.web?.uri).map((c: any) => ({
        title: c.web.title || new URL(c.web.uri).hostname,
        uri: c.web.uri,
        trustScore: 70,
        reliabilityBadge: 'VERIFIED' as const
      })).slice(0, 3);

      const results: FactCheckResult[] = data.map((item: any, i: number) => ({
          id: `trend-${Date.now()}-${i}`,
          claim: item.headline,
          verdict: normalizeVerdict(item.verdict),
          confidenceLevel: ConfidenceLevel.UNVERIFIED,
          explanation: item.summary,
          headline: item.headline,
          reasoningTimeline: [],
          sources: sources,
          timestamp: Date.now(),
          confidenceScore: 70,
          communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
          author: "Truth Engine"
      }));

      // Cache findings in the global state database
      db.content.saveTrending(results, langCode);
      return results;
    } catch (e) { return []; }
};

