import { BarChart2 } from 'lucide-react';

import React, { useEffect, useState, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { fetchTrendingDebunks, fetchRealTopNews } from '../services/geminiService';
import { db } from '../services/db';
import { FactCheckResult, TickerItem, Activity as ActivityType } from '../types';
import { VerdictBadge } from '../components/VerdictBadge';
import { PollWidget } from '../components/PollWidget';
import { useAuth } from '../context/AuthContext';
import { useLanguage, LANGUAGES } from '../context/LanguageContext';
import { RefreshCw, Share2, Clock, Zap, Cpu, ShieldCheck, MessageSquare, TrendingUp, BarChart, Radio, Globe, Shield } from 'lucide-react';
import { Logo } from '../components/Logo';

export const Home: React.FC = () => {
  const { language, t } = useLanguage();
  const langName = LANGUAGES.find(l => l.code === language)?.name || 'English';

  const [localChecks, setLocalChecks] = useState<FactCheckResult[]>(() => db.content.getFeed());
  const [trendingChecks, setTrendingChecks] = useState<FactCheckResult[]>(() => db.content.getTrending(language));
  const [tickerItems, setTickerItems] = useState<TickerItem[]>(() => db.analytics.getTicker(language));

  const [loading, setLoading] = useState(false);
  const [recentActivities, setRecentActivities] = useState<ActivityType[]>([]);
  const [lastTickerUpdate, setLastTickerUpdate] = useState<Date>(new Date());

  const { user, castVote, getRecentActivities, activeUsersCount } = useAuth();

  const loadTicker = async () => {
    const news = await fetchRealTopNews(language, langName);
    if (news?.length) {
      setTickerItems(news);
      setLastTickerUpdate(new Date());
    }
  };

  const loadContent = async (force = false) => {
    if (trendingChecks.length > 0 && !force) {
        if (db.content.isCacheStale(language)) {
            fetchTrendingDebunks(language, langName, true).then(fresh => setTrendingChecks(fresh));
        }
        return;
    }

    setLoading(true);
    try {
        const trending = await fetchTrendingDebunks(language, langName, force);
        setTrendingChecks(trending);
    } catch (e) { 
        console.error("News sync failed:", e); 
    } finally { 
        setLoading(false); 
    }
  };

  useEffect(() => {
    Promise.all([
        loadContent(false),
        loadTicker(),
        setRecentActivities(getRecentActivities())
    ]);

    const tickerInterval = setInterval(loadTicker, 180000);
    const activityInterval = setInterval(() => setRecentActivities(getRecentActivities()), 8000);

    return () => {
      clearInterval(tickerInterval);
      clearInterval(activityInterval);
    };
  }, [language]);

  const handleVote = (id: string, opt: 'trueVotes' | 'falseVotes' | 'misleadingVotes') => {
    castVote(id, opt);
    const upd = (l: FactCheckResult[]) => l.map(i => i.id === id ? { ...i, communityPoll: { ...i.communityPoll, [opt]: i.communityPoll[opt]+1, total: i.communityPoll.total+1 } } : i);
    setTrendingChecks(upd); 
    setLocalChecks(upd);
  };

  const feedItems = useMemo(() => {
    return [...localChecks, ...trendingChecks].sort((a, b) => b.timestamp - a.timestamp);
  }, [localChecks, trendingChecks]);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 relative">

      {/* BACKGROUND DECORATIVE LOGO */}
      <div className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-[0.02] pointer-events-none z-0">
          <Logo size={800} animated={true} />
      </div>

      {/* GLOBAL INTELLIGENCE TICKER */}
      <div key={language} className="bg-slate-900/80 backdrop-blur-xl border border-white/5 mb-12 rounded-[2rem] overflow-hidden py-4 relative flex items-center shadow-3xl group animate-fade-in border-l-8 border-l-primary-600">
         <div className="bg-red-600 text-white text-[11px] font-black px-6 py-2 ml-4 rounded-xl z-10 flex items-center gap-3 shadow-lg shadow-red-900/40">
             <div className="w-2 h-2 rounded-full bg-white animate-pulse"></div>
             NETWORK ALERTS
         </div>

         <div className="flex-1 overflow-hidden pointer-events-none">
             <div className="animate-ticker">
                 {(tickerItems.length > 0 ? [...tickerItems, ...tickerItems] : []).map((item, i) => (
                     <div key={i} className="flex items-center gap-10 px-12 border-r border-white/5">
                        <span className="text-[10px] font-black text-primary-500 uppercase tracking-[0.3em]">{item.source}</span>
                        <span className="text-base font-bold text-white whitespace-nowrap tracking-tight">{item.headline}</span>
                        <span className={`text-[10px] font-black px-3 py-1 rounded-lg border ${item.verdict === 'TRUE' ? 'border-green-500/30 text-green-500 bg-green-500/5' : 'border-red-500/30 text-red-500 bg-red-500/5'}`}>
                            {item.verdict}
                        </span>
                     </div>
                 ))}
                 {tickerItems.length === 0 && (
                    <div className="px-12 text-slate-600 text-sm font-black uppercase tracking-widest animate-pulse">Establishing Neural Link...</div>
                 )}
             </div>
         </div>
         <div className="hidden lg:flex items-center gap-3 px-8 border-l border-white/5 bg-slate-900/90 z-10 text-slate-500 text-[11px] font-black uppercase tracking-widest">
            <Clock className="w-4 h-4" />
            {lastTickerUpdate.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 relative z-10">
        <div className="lg:col-span-8 space-y-12">
            <div className="flex items-center justify-between px-4">
                <div className="flex items-center gap-6">
                    <div className="p-3 bg-primary-600/10 rounded-2xl border border-primary-500/20">
                        <Radio className="w-6 h-6 text-primary-500 animate-pulse" />
                    </div>
                    <div>
                        <h2 className="text-4xl font-black text-white tracking-tighter uppercase italic leading-none">{t('nav_feed')}</h2>
                        <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.3em] mt-2">Active Intelligence Monitoring</p>
                    </div>
                </div>
                <button onClick={() => loadContent(true)} className="p-4 bg-slate-900/50 backdrop-blur-md border border-white/5 rounded-2xl hover:bg-slate-800 hover:border-primary-500 transition-all group shadow-xl">
                    <RefreshCw className={`w-6 h-6 text-primary-400 group-hover:rotate-180 transition-transform duration-700 ${loading ? 'animate-spin' : ''}`} />
                </button>
            </div>

            {loading && !feedItems.length ? (
                <div className="grid gap-8">
                    {[1, 2].map(i => <div key={i} className="bg-slate-900/40 rounded-[3rem] h-80 border border-white/5 overflow-hidden relative">
                        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/5 to-transparent -translate-x-full animate-[shimmer_2s_infinite]"></div>
                    </div>)}
                </div>
