export const VerdictBadge: React.FC<Props> = ({ verdict, level, className = '', isGrounded = true }) => {
  const getStyle = () => {
    // Priority: If verdict is explicitly provided and is Misleading, use that first
    if (verdict === VerdictType.MISLEADING) return {
      bg: 'bg-amber-500',
      shadow: 'shadow-amber-900/40',
      glow: 'shadow-[0_0_15px_rgba(245,158,11,0.5)]',
      icon: <AlertTriangle className="w-4 h-4" />,
      label: 'Misleading'
    };

    switch (level) {
      case ConfidenceLevel.AUTHENTIC:
        return {
          bg: 'bg-green-600',
          shadow: 'shadow-green-900/40',
          glow: 'shadow-[0_0_15px_rgba(34,197,94,0.5)]',
          icon: <CheckCircle2 className="w-4 h-4" />,
          label: 'Verified'
        };
      case ConfidenceLevel.LIKELY_AUTHENTIC:
        return {
          bg: 'bg-green-500/80',
          shadow: 'shadow-green-900/30',
          glow: '',
          icon: <CheckCircle2 className="w-4 h-4" />,
          label: 'Likely True'
        };
      case ConfidenceLevel.FABRICATED:
        return {
          bg: 'bg-red-600',
          shadow: 'shadow-red-900/40',
          glow: 'shadow-[0_0_15px_rgba(239,68,68,0.5)]',
          icon: <XCircle className="w-4 h-4" />,
          label: 'Fake News'
        };
      case ConfidenceLevel.LIKELY_FABRICATED:
        return {
          bg: 'bg-red-500/80',
          shadow: 'shadow-red-900/30',
          glow: '',
          icon: <XCircle className="w-4 h-4" />,
          label: 'Likely Fake'
        };
      case ConfidenceLevel.UNVERIFIED:
        return {
          bg: 'bg-slate-700',
          shadow: 'shadow-slate-900/30',
          glow: '',
          icon: <HelpCircle className="w-4 h-4" />,
          label: 'Unverified'
        };
      default:
        if (verdict === VerdictType.TRUE) return {
          bg: 'bg-green-600', shadow: 'shadow-green-900/40', glow: '', icon: <CheckCircle2 className="w-4 h-4" />, label: 'Verified'
        };
        if (verdict === VerdictType.FALSE) return {
          bg: 'bg-red-600', shadow: 'shadow-red-900/40', glow: '', icon: <XCircle className="w-4 h-4" />, label: 'Fake'
        };
        return {
          bg: 'bg-slate-800',
          shadow: 'shadow-slate-900/30',
          glow: '',
          icon: <Activity className="w-4 h-4 animate-pulse" />,
          label: 'Auditing...'
        };
    }
  };

  const style = getStyle();

  return (
    <div className={`inline-flex items-center gap-2.5 ${style.bg} ${style.glow} text-white px-5 py-2.5 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-2xl ${style.shadow} transition-all hover:scale-105 ${className}`}>
      {style.icon}
      {style.label}
      {isGrounded && level !== ConfidenceLevel.UNVERIFIED && (
        <div className="ml-1 border-l border-white/20 pl-2" title="Grounded Evidence">
          <ShieldCheck className="w-3.5 h-3.5 text-white/80" />
        </div>
      )}
    </div>
  );
};

