          explanation: item.summary,
          headline: item.headline,
          reasoningTimeline: [],
          sources: [],
          timestamp: Date.now() - (i * 3600000),
          imageUrl: getFuturisticImage(item.category),
          confidenceScore: 85,
          communityPoll: { 
            trueVotes: Math.floor(Math.random()*20), 
            falseVotes: Math.floor(Math.random()*20), 
            misleadingVotes: Math.floor(Math.random()*20), 
            total: 30 
          },
          author: "Neural Node"
      }));
      db.content.saveTrending(results, langCode);
      return results;
    } catch (e) { return []; }
};

