    // Explicit Misleading override for consistent color regardless of confidence level string
    if (verdict === VerdictType.MISLEADING) return {
      bg: 'bg-amber-500',
      shadow: 'shadow-amber-900/60',
      glow: 'shadow-[0_0_20px_rgba(245,158,11,0.6)]',
      icon: <AlertTriangle className="w-4 h-4" />,
      label: 'Misleading'
    };

    switch (level) {
      case ConfidenceLevel.AUTHENTIC:
        return {
          bg: 'bg-green-600',
          shadow: 'shadow-green-900/40',
          glow: 'shadow-[0_0_20px_rgba(34,197,94,0.6)]',
          icon: <CheckCircle2 className="w-4 h-4" />,
          label: 'Verified'
        };
      case ConfidenceLevel.LIKELY_AUTHENTIC:
        return {
          bg: 'bg-green-500/90',
          shadow: 'shadow-green-900/30',
          glow: 'shadow-[0_0_10px_rgba(34,197,94,0.3)]',
          icon: <CheckCircle2 className="w-4 h-4" />,
          label: 'Likely True'
        };
      case ConfidenceLevel.FABRICATED:
        return {
          bg: 'bg-red-600',
          shadow: 'shadow-red-900/60',
          glow: 'shadow-[0_0_20px_rgba(239,68,68,0.7)]',
          icon: <XCircle className="w-4 h-4" />,
          label: 'Fake News'
        };
      case ConfidenceLevel.LIKELY_FABRICATED:
        return {
          bg: 'bg-red-500/90',
          shadow: 'shadow-red-900/30',
          glow: 'shadow-[0_0_10px_rgba(239,68,68,0.4)]',
          icon: <XCircle className="w-4 h-4" />,
          label: 'Likely Fake'
        };
      default:
        if (verdict === VerdictType.TRUE) return {
          bg: 'bg-green-600', shadow: 'shadow-green-900/40', glow: 'shadow-[0_0_15px_rgba(34,197,94,0.4)]', icon: <CheckCircle2 className="w-4 h-4" />, label: 'Verified'
        };
